def high_growth_sheet_label(name: str, language: str | None = None) -> str:
    lang = (language or REPORT_LANGUAGE or "ZH").strip().upper()
    item = HIGH_GROWTH_SHEET_MAP.get(str(name))
    if not item:
        return str(name)
    return item.get("en" if lang == "EN" else "zh", str(name))

def high_growth_column_label(key: str, language: str | None = None) -> str:
    lang = (language or REPORT_LANGUAGE or "ZH").strip().upper()
    key_str = str(key)
    if key_str.startswith("rev_"):
        ym = key_str.replace("rev_", "")
        return f"營收{ym}" if lang == "ZH" else (f"Revenue {ym}" if lang == "EN" else f"營收{ym}\n(Revenue {ym})")
    if key_str.startswith("yoy_"):
        ym = key_str.replace("yoy_", "")
        return f"營收年增率{ym}" if lang == "ZH" else (f"Revenue YoY {ym}" if lang == "EN" else f"營收年增率{ym}\n(Revenue YoY {ym})")
    item = HIGH_GROWTH_COLUMN_MAP.get(key_str)
    if not item:
        return key_str
    zh = item.get("zh", str(key))
    en = item.get("en", str(key))
    if lang == "ZH":
        return zh
    if lang == "EN":
        return en
    return f"{zh}\n({en})"

def localize_high_growth_dataframe_columns(df: pd.DataFrame, language: str | None = None) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame):
        return df
    out = df.copy()
    out.columns = [high_growth_column_label(c, language) for c in out.columns]
    return out

def high_growth_model_definition_text(language: str | None = None) -> str:
    lang = (language or REPORT_LANGUAGE or "ZH").strip().upper()
    zh = "40%預測Q2 EPS + 25%EPS加速度 + 20%營收加速度 + 15%估值(PE/PEG)；actual_q1_eps只作預測誤差/黑馬指標驗證"
    en = "40% Predicted Q2 EPS + 25% EPS Acceleration + 20% Revenue Acceleration + 15% Valuation (PE/PEG); actual_q1_eps is only used to validate prediction_error / EPS Surprise"
    if lang == "ZH":
        return zh
    if lang == "EN":
        return en
    return zh + " / " + en

