# R5N7D_REVENUE_PIPELINE_CONSISTENCY_FIX_20260613:
# 統一月營收資料管線路徑與來源追溯。
# 原則：raw 保留官方原始回應；normalized 保留清洗後中間檔；sii/otc 為正式可讀取 cache；archive 保留覆蓋前版本。
def _r5n7d_revenue_pipeline_dir(stage: str, market_type: str | None = None, source_key: str = "") -> Path:
    stage = str(stage or "").strip().lower()
    mt = normalize_market_type(market_type)
    root_map = {
        "raw": REVENUE_RAW_CACHE_DIR,
        "normalized": REVENUE_NORMALIZED_CACHE_DIR,
        "archive": REVENUE_ARCHIVE_CACHE_DIR,
        "final": REVENUE_CACHE_DIR,
    }
    root = root_map.get(stage, REVENUE_CACHE_DIR)
    if mt in ("sii", "otc"):
        root = root / mt
    if source_key:
        root = root / re.sub(r"[^A-Za-z0-9_\-]", "_", str(source_key))[:60]
    root.mkdir(parents=True, exist_ok=True)
    return root

def _r5n7d_archive_existing_file(path: Path, reason: str = "overwrite") -> Path | None:
    try:
        p = Path(path)
        if not p.exists() or p.stat().st_size <= 0:
            return None
        mt = normalize_market_type(p.name)
        out_dir = _r5n7d_revenue_pipeline_dir("archive", mt)
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        out = out_dir / f"{p.stem}_{reason}_{stamp}{p.suffix}"
        shutil.copy2(p, out)
        return out
    except Exception as exc:
        log_warning(f"[R5N7D][ARCHIVE_FAIL] file={path}｜{exc}")
        return None

def _r5n7d_manifest_path() -> Path:
    return REVENUE_CACHE_DIR / "data_pipeline_manifest.json"

def _r5n7d_append_manifest(record: dict):
    try:
        path = _r5n7d_manifest_path()
        path.parent.mkdir(parents=True, exist_ok=True)
        data = []
        if path.exists() and path.stat().st_size > 0:
            try:
                loaded = json.loads(path.read_text(encoding="utf-8"))
                if isinstance(loaded, list):
                    data = loaded
            except Exception:
                data = []
        rec = dict(record or {})
        rec.setdefault("created_at", datetime.now().strftime("%Y-%m-%d %H:%M:%S"))
        data.append(rec)
        data = data[-2000:]
        path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as exc:
        log_warning(f"[R5N7D][MANIFEST_WRITE_FAIL] {exc}")

def _r5n7d_save_df_csv(df: pd.DataFrame, path: Path, stage: str, month: str, market_type: str | None, source_key: str = "") -> Path | None:
    try:
        if df is None or df.empty:
            return None
        p = Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        _r5n7d_archive_existing_file(p, reason=stage)
        df.to_csv(p, index=False, encoding="utf-8-sig")
        _r5n7d_append_manifest({
            "stage": stage,
            "revenue_month": RevenueAccelerationEngine.normalize_month(month),
            "market_type": normalize_market_type(market_type) or "all",
            "source_key": source_key,
            "path": str(p),
            "rows": int(len(df)),
            "bytes": int(p.stat().st_size) if p.exists() else 0,
            "status": "PASS",
        })
        return p
    except Exception as exc:
        log_warning(f"[R5N7D][CSV_WRITE_FAIL] stage={stage} month={month} market={market_type} file={path}｜{exc}")
        return None

def _r5n8d_write_official_source_gate_csv(month: str, gate_df: pd.DataFrame | None, gate_name: str = "index04") -> Path | None:
    """R5N8D：輸出官方資料來源 Gate CSV。
    專門讓現場查核：download / unzip / parse / cache / db / report 是否閉環。
    """
    try:
        m = RevenueAccelerationEngine.normalize_month(month)
        if not m:
            m = str(month or "unknown")
        if gate_df is None or gate_df.empty:
            return None
        out_dir = TWSE_INDEX04_GATE_REPORT_DIR / m
        out_dir.mkdir(parents=True, exist_ok=True)
        safe_name = re.sub(r"[^A-Za-z0-9_\-]", "_", str(gate_name or "gate"))[:60]
        out = out_dir / f"{m}_{safe_name}_gate.csv"
        gate_df.to_csv(out, index=False, encoding="utf-8-sig")
        _r5n7d_append_manifest({
            "stage": "official_source_gate",
            "revenue_month": m,
            "market_type": "all",
            "source_key": safe_name,
            "path": str(out),
            "rows": int(len(gate_df)),
            "bytes": int(out.stat().st_size) if out.exists() else 0,
            "status": "PASS",
        })
        log_info(f"[R5N8D][OFFICIAL_SOURCE_GATE][WRITE] month={m} gate={safe_name} rows={len(gate_df)} file={out}")
        return out
    except Exception as exc:
        log_warning(f"[R5N8D][OFFICIAL_SOURCE_GATE][WRITE_FAIL] month={month} gate={gate_name}｜{exc}")
        return None

def _r5n7d_is_revenue_not_due(month: str, today: datetime | None = None) -> bool:
    """月報未到期判斷。對 YYYYMM，下一月10日以前不應列 FAIL。"""
    m = RevenueAccelerationEngine.normalize_month(month)
    if not m:
        return False
    today = today or datetime.now()
    y, mm = int(m[:4]), int(m[4:6])
    due_y, due_m = y, mm + 1
    if due_m > 12:
        due_y += 1
        due_m = 1
    due_date = datetime(due_y, due_m, 10)
    return today <= due_date

def _r5n7d_exclude_non_revenue_universe(df: pd.DataFrame) -> pd.DataFrame:
    """EPS/月營收驗證母體排除ETF與特殊商品，避免把不適用標的列為缺漏。"""
    if df is None or df.empty:
        return pd.DataFrame()
    x = df.copy()
    sid = x.get("stock_id", pd.Series("", index=x.index)).astype(str)
    name = x.get("stock_name", pd.Series("", index=x.index)).astype(str)
    market = x.get("market", pd.Series("", index=x.index)).astype(str)
    is_etf = pd.to_numeric(x.get("is_etf", pd.Series(0, index=x.index)), errors="coerce").fillna(0).astype(int) if "is_etf" in x.columns else pd.Series(0, index=x.index)
    special = (
        is_etf.eq(1) | market.eq("ETF") | sid.str.startswith(("00", "01", "02", "91")) |
        name.str.contains("ETF|ETN|指數|期貨|權證|特別股|受益證券", regex=True, na=False)
    )
    return x.loc[~special].copy()


def normalize_market_type(value) -> str:
    s = str(value or "").strip()
    if not s:
        return ""
    if s in MARKET_TYPE_MAP:
        return MARKET_TYPE_MAP[s]
    low = s.lower()
    if "otc" in low or "上櫃" in s or "tpex" in low or "_o" in low:
        return "otc"
    if "sii" in low or "上市" in s or "twse" in low or "_l" in low:
        return "sii"
    return ""

def market_type_to_label(value) -> str:
    mt = normalize_market_type(value)
    return "上市" if mt == "sii" else ("上櫃" if mt == "otc" else "")

def _r5n8c_market_label_to_type(value) -> str:
    """R5N8C：股票主檔 market 欄位轉 market_type，供所有外部資料 merge / gate 共用。"""
    return normalize_market_type(value)


def _r5n8c_build_market_map(master_df: pd.DataFrame) -> dict:
    """R5N8C：建立 stock_id -> market_type 對照，避免只靠外部資料 source_url 推測市場別。"""
    if master_df is None or master_df.empty:
        return {}
    x = master_df.copy()
    if "stock_id" not in x.columns:
        return {}
    x["stock_id"] = x["stock_id"].map(normalize_stock_id)
    if "market_type" in x.columns:
        mt = x["market_type"].map(normalize_market_type)
    else:
        mt = x.get("market", pd.Series("", index=x.index)).map(normalize_market_type)
    x["_market_type"] = mt
    x = x[(x["stock_id"] != "") & (x["_market_type"] != "")].drop_duplicates("stock_id", keep="last")
    return dict(zip(x["stock_id"], x["_market_type"]))


def _r5n8c_prepare_external_latest_df(df: pd.DataFrame, master_df: pd.DataFrame | None, table_name: str = "", order_col: str = "") -> pd.DataFrame:
    """R5N8C：外部表進入策略/爆發股 merge 前，強制收斂成 stock_id 唯一。

    修正重點：
    1. external_revenue_history 已開始有 market_type，舊版 _latest_by_stock 只用 stock_id+MAX(month)
       會在 legacy_all / sii / otc 並存時造成同一 stock_id 多列。
    2. 爆發股寫入 prebreakout_signal_daily 的主鍵是 stock_id + signal_date；
       若 merge 後一檔股票被放大成多列，就會觸發 UNIQUE constraint。
    3. 本函式會優先保留 market_type 與 stocks_master.market 相符的列，其次保留最後更新列。
    """
    if df is None or df.empty:
        return pd.DataFrame(columns=["stock_id"])
    x = df.copy()
    if "stock_id" not in x.columns:
        return pd.DataFrame(columns=["stock_id"])
    x["stock_id"] = x["stock_id"].map(normalize_stock_id)
    x = x[x["stock_id"] != ""].copy()
    if x.empty:
        return x

    market_map = _r5n8c_build_market_map(master_df) if master_df is not None else {}
    x["_expected_market_type"] = x["stock_id"].map(market_map).fillna("")
    if "market_type" in x.columns:
        x["_row_market_type"] = x["market_type"].map(normalize_market_type)
    elif "source_type" in x.columns:
        x["_row_market_type"] = x["source_type"].map(normalize_market_type)
    elif "source_url" in x.columns:
        x["_row_market_type"] = x["source_url"].map(normalize_market_type)
    else:
        x["_row_market_type"] = ""

    # priority: exact market match > unknown > mismatch. Unknown kept as fallback to avoid dropping legacy rows.
    x["_market_priority"] = np.select(
        [
            x["_expected_market_type"].ne("") & x["_row_market_type"].eq(x["_expected_market_type"]),
            x["_row_market_type"].eq(""),
        ],
        [2, 1],
        default=0,
    )
    if order_col and order_col in x.columns:
        x["_order_key"] = x[order_col].astype(str)
    else:
        x["_order_key"] = ""
    if "update_time" not in x.columns:
        x["update_time"] = ""
    dup_before = int(x.duplicated("stock_id", keep=False).sum())
    x = (
        x.sort_values(["stock_id", "_market_priority", "_order_key", "update_time"])
         .drop_duplicates("stock_id", keep="last")
         .drop(columns=[c for c in ["_expected_market_type", "_row_market_type", "_market_priority", "_order_key"] if c in x.columns])
    )
    if dup_before > 0:
        log_warning(f"[R5N8C][LATEST_BY_STOCK_DEDUP] table={table_name} order_col={order_col} duplicated_rows={dup_before} final_rows={len(x)}")
    return x


def _r5n8c_filter_strategy_universe(df: pd.DataFrame) -> pd.DataFrame:
    """R5N8C：爆發股/高成長候選用普通股母體；ETF/權證/特殊商品不進候選與缺漏統計。"""
    return _r5n7d_exclude_non_revenue_universe(df)

