# R5N_REVENUE_CACHE_UI_MONTH_SELECTOR_20260608：UI 指定月份區間下載，不再寫死 202602/202603/202604。
# 位置決議：高成長 EPS 分頁第二排最右側。
def normalize_yyyymm(value) -> str:
    """R5N：將 UI/設定輸入正規化為 YYYYMM。"""
    return RevenueAccelerationEngine.normalize_month(value)


def build_month_range(start_month: str, end_month: str) -> list[str]:
    """R5N：由起始/結束月份建立 YYYYMM 清單，避免每月改程式。

    Example:
        build_month_range("202601", "202604")
        -> ["202601", "202602", "202603", "202604"]
    """
    start = normalize_yyyymm(start_month)
    end = normalize_yyyymm(end_month)
    if not start or not end:
        raise ValueError(f"月份格式錯誤，需為 YYYYMM；start={start_month}, end={end_month}")
    sy, sm = int(start[:4]), int(start[4:6])
    ey, em = int(end[:4]), int(end[4:6])
    if (sy, sm) > (ey, em):
        raise ValueError(f"起始月份不可大於結束月份：{start} > {end}")
    months = []
    y, m = sy, sm
    while (y, m) <= (ey, em):
        months.append(f"{y:04d}{m:02d}")
        m += 1
        if m > 12:
            y += 1
            m = 1
    return months


def revenue_month_options(back_years: int = 2, forward_months: int = 0) -> list[str]:
    """R5N：產生 UI 下拉月份選項。預設提供近兩年到本月。"""
    today = datetime.now()
    start_y = today.year - int(back_years or 0)
    start_m = 1
    end_y, end_m = today.year, today.month + int(forward_months or 0)
    while end_m > 12:
        end_y += 1
        end_m -= 12
    return build_month_range(f"{start_y:04d}{start_m:02d}", f"{end_y:04d}{end_m:02d}")


def safe_read_html_tables(html_text, source_label: str = "") -> tuple[list[pd.DataFrame], str, str]:
    """R5L：安全 HTML 表格解析。

    MOPS ajax_t21sc04 歷史月營收常透過 pd.read_html 解析。舊版只依賴
    環境預設 lxml，EXE 內缺 lxml 時會造成 202602/202603 補抓 0 筆。
    此函式依序嘗試 lxml / bs4 / html5lib，並回傳使用 parser 與完整錯誤，
    供 Trace/報表判斷 DEPENDENCY_MISSING 或 PARSE_ROWS_ZERO。
    """
    html = str(html_text or "")
    if not html.strip():
        return [], "", "EMPTY_HTML"
    errors = []
    for flavor in (["lxml"], ["bs4"], ["html5lib"]):
        parser_name = flavor[0]
        try:
            tables = pd.read_html(io.StringIO(html), flavor=flavor)
            if tables:
                log_info(f"[R5L][SAFE_READ_HTML] source={source_label} parser={parser_name} tables={len(tables)}")
                return tables, parser_name, ""
            errors.append(f"{parser_name}:tables=0")
        except Exception as exc:
            errors.append(f"{parser_name}:{exc}")
    err = " | ".join(errors)
    log_warning(f"[R5L][SAFE_READ_HTML][FAIL] source={source_label} error={err}")
    return [], "", err



def get_high_growth_report_path(date_str: str | None = None, quarters: list[str] | None = None) -> Path:
    d = date_str or datetime.now().strftime("%Y%m%d")
    qtag = "".join(quarters or HIGH_GROWTH_DEFAULT_QUARTERS) or "Q1"
    HIGH_GROWTH_REPORT_DIR.mkdir(parents=True, exist_ok=True)
    return HIGH_GROWTH_REPORT_DIR / f"high_growth_eps_engine_v4_{qtag}_{d}.xlsx"

def get_high_growth_report_path_by_language(date_str: str | None = None, quarters: list[str] | None = None, language: str = "ZH") -> Path:
    """V4.14：高成長EPS報表固定輸出中文/英文兩份；UI 不受語言參數影響。"""
    base = get_high_growth_report_path(date_str=date_str, quarters=quarters)
    lang = str(language or "ZH").strip().upper()
    if lang == "EN":
        return base.with_name(base.stem + "_EN.xlsx")
    if lang == "BILINGUAL":
        return base.with_name(base.stem + "_BILINGUAL.xlsx")
    return base.with_name(base.stem + "_ZH.xlsx")


def normalize_high_growth_quarters(quarters=None) -> list[str]:
    if quarters is None:
        return list(HIGH_GROWTH_DEFAULT_QUARTERS)
    if isinstance(quarters, str):
        raw = re.split(r"[,/|;\s]+", quarters.strip().upper())
    else:
        raw = [str(q).strip().upper() for q in quarters]
    out = []
    for q in raw:
        if not q:
            continue
        q = q.replace("季度", "").replace("第", "").replace("季", "")
        if q in ("1", "一"):
            q = "Q1"
        elif q in ("2", "二"):
            q = "Q2"
        elif q in ("3", "三"):
            q = "Q3"
        elif q in ("4", "四"):
            q = "Q4"
        if q in HIGH_GROWTH_QUARTER_REVENUE_MONTHS and q not in out:
            out.append(q)
    return out or list(HIGH_GROWTH_DEFAULT_QUARTERS)


class RevenueAccelerationEngine:
    """月營收加速度引擎：以所選季度對應月份檢查 YoY 暴增與階梯式月月走高。"""

    def __init__(self, db: DBManager, min_yoy: float = HIGH_GROWTH_MIN_YOY):
        self.db = db
        self.min_yoy = float(min_yoy)

    def _table_exists(self, table_name: str) -> bool:
        try:
            with self.db.lock:
                row = self.db.conn.cursor().execute(
                    "SELECT name FROM sqlite_master WHERE type='table' AND name=?", (table_name,)
                ).fetchone()
            return row is not None
        except Exception:
            return False

    def _read_sql(self, sql: str, params=None) -> pd.DataFrame:
        try:
            with self.db.lock:
                return pd.read_sql_query(sql, self.db.conn, params=params or [])
        except Exception as exc:
            log_warning(f"[RevenueAccelerationEngine] SQL讀取失敗：{exc}｜SQL={sql[:120]}")
            return pd.DataFrame()

    @staticmethod
    def normalize_month(value) -> str:
        """月營收月份正規化。

        R3 修正重點：
        - 支援 OpenAPI / DB / Excel 可能出現的 115年04月、115/04、115-04、11504、202604、2026年04月。
        - 舊版只移除 - /，遇到「115年04月」會無法命中，導致 external_revenue 有資料但 required_months 全部 MISSING。
        - 失敗時回傳空字串，不用目前月份硬補，避免偽造覆蓋率。
        """
        if value is None:
            return ""
        s = str(value).strip().replace("\ufeff", "")
        if not s or s.lower() in ("nan", "none", "null", "<na>"):
            return ""
        if re.fullmatch(r"\d+\.0+", s):
            try:
                s = str(int(float(s)))
            except Exception:
                pass

        # 西元：2026年04月 / 2026-04 / 2026/4 / 202604
        m = re.search(r"(20\d{2}|19\d{2})\D{0,3}(\d{1,2})", s)
        if m:
            y = int(m.group(1)); mm = int(m.group(2))
            if 1 <= mm <= 12:
                return f"{y:04d}{mm:02d}"

        # 民國：115年04月 / 115/04 / 115-4 / 民國115年4月 / 11504
        m = re.search(r"(\d{2,3})\D{0,3}(\d{1,2})", s)
        if m:
            y = int(m.group(1)); mm = int(m.group(2))
            if y < 1911 and 1 <= mm <= 12:
                return f"{y + 1911:04d}{mm:02d}"

        digits = re.sub(r"\D", "", s)
        if len(digits) >= 6:
            # 202604
            y = int(digits[:4]); mm = int(digits[4:6])
            if y >= 1911 and 1 <= mm <= 12:
                return f"{y:04d}{mm:02d}"
        if len(digits) == 5:
            # 11504
            y = int(digits[:3]); mm = int(digits[3:5])
            if 1 <= mm <= 12:
                return f"{y + 1911:04d}{mm:02d}"
        return ""

    def required_months(self, quarters=None) -> list[str]:
        months = []
        for q in normalize_high_growth_quarters(quarters):
            for m in HIGH_GROWTH_QUARTER_REVENUE_MONTHS.get(q, []):
                if m not in months:
                    months.append(m)
        return months

    def load_monthly_revenue(self, quarters=None) -> pd.DataFrame:
        months = self.required_months(quarters)
        parts = []
        for table, priority in [("external_revenue_history", 1), ("external_revenue", 2)]:
            if not self._table_exists(table):
                continue
            df = self._read_sql(f"SELECT stock_id, revenue_month, revenue, mom, yoy, cumulative_revenue, cumulative_yoy, source_date, update_time FROM {table}")
            if df is None or df.empty:
                continue
            df = df.copy()
            df["stock_id"] = df["stock_id"].map(normalize_stock_id)
            df["revenue_month_norm"] = df["revenue_month"].map(self.normalize_month)
            df["revenue"] = pd.to_numeric(df.get("revenue"), errors="coerce")
            df["yoy"] = pd.to_numeric(df.get("yoy"), errors="coerce")
            df["mom"] = pd.to_numeric(df.get("mom"), errors="coerce")
            df["source_table"] = table
            df["_priority"] = priority
            df = df[df["revenue_month_norm"].isin(months)].copy()
            parts.append(df)
        if not parts:
            return pd.DataFrame(columns=["stock_id", "revenue_month_norm", "revenue", "yoy", "mom", "source_table"])
        x = pd.concat(parts, ignore_index=True)
        x = x.sort_values(["stock_id", "revenue_month_norm", "_priority"], ascending=[True, True, True])
        x = x.drop_duplicates(["stock_id", "revenue_month_norm"], keep="first")
        return x.drop(columns=["_priority"], errors="ignore")

    def build_revenue_features(self, master: pd.DataFrame, quarters=None) -> tuple[pd.DataFrame, pd.DataFrame]:
        quarters = normalize_high_growth_quarters(quarters)
        months = self.required_months(quarters)
        rev = self.load_monthly_revenue(quarters)
        base = master[["stock_id"]].drop_duplicates().copy() if master is not None and not master.empty else pd.DataFrame(columns=["stock_id"])
        if base.empty:
            return base, rev
        for m in months:
            mdf = rev[rev["revenue_month_norm"].eq(m)][["stock_id", "revenue", "yoy", "mom", "source_table"]].copy() if not rev.empty else pd.DataFrame(columns=["stock_id", "revenue", "yoy", "mom", "source_table"])
            mdf = mdf.rename(columns={"revenue": f"rev_{m}", "yoy": f"yoy_{m}", "mom": f"mom_{m}", "source_table": f"rev_source_{m}"})
            base = base.merge(mdf, on="stock_id", how="left")
        yoy_cols = [f"yoy_{m}" for m in months]
        rev_cols = [f"rev_{m}" for m in months]
        for c in yoy_cols + rev_cols:
            if c not in base.columns:
                base[c] = np.nan
            base[c] = pd.to_numeric(base[c], errors="coerce")
        base["selected_quarters"] = "+".join(quarters)
        base["selected_revenue_months"] = ",".join(months)
        base["revenue_month_count_required"] = len(months)
        base["revenue_month_count_hit"] = base[rev_cols].notna().sum(axis=1) if rev_cols else 0
        base["avg_revenue_yoy"] = base[yoy_cols].mean(axis=1, skipna=True) if yoy_cols else np.nan
        base["min_revenue_yoy"] = base[yoy_cols].min(axis=1, skipna=True) if yoy_cols else np.nan
        base["revenue_yoy_gate"] = base[yoy_cols].ge(self.min_yoy).all(axis=1) if yoy_cols else False
        base["revenue_complete_gate"] = base["revenue_month_count_hit"].eq(base["revenue_month_count_required"])
        if len(rev_cols) >= 2:
            base["revenue_stair_gate"] = True
            for left, right in zip(rev_cols[:-1], rev_cols[1:]):
                base["revenue_stair_gate"] = base["revenue_stair_gate"] & (base[right] > base[left])
        else:
            base["revenue_stair_gate"] = False
        base["revenue_strict_gate"] = base["revenue_complete_gate"] & base["revenue_yoy_gate"] & base["revenue_stair_gate"]
        base["revenue_acceleration_score"] = np.clip(40 + base["avg_revenue_yoy"].fillna(0) * 0.6 + base["revenue_month_count_hit"] * 3, 0, 100).round(2)
        base["revenue_data_quality"] = np.where(base["revenue_strict_gate"], "STRICT", np.where(base["revenue_month_count_hit"] > 0, "PARTIAL_OR_PROXY", "MISSING"))
        return base, rev


class RevenueCacheManager:
    """R5N7：月營收本機 Cache 管理器，支援上市/上櫃分流。

    固定結構：
    data/revenue_cache/sii/revenue_YYYYMM_sii.csv
    data/revenue_cache/sii/index04_c04003/
    data/revenue_cache/otc/revenue_YYYYMM_otc.csv
    data/revenue_cache/otc/mops_t21sc03/

    為了保留舊版流程，也同步保留舊檔 revenue_YYYYMM.csv 作為相容讀取。
    """

    def __init__(self, cache_dir: Path | None = None):
        self.cache_dir = Path(cache_dir or REVENUE_CACHE_DIR)
        self.raw_dir = REVENUE_RAW_CACHE_DIR
        self.normalized_dir = REVENUE_NORMALIZED_CACHE_DIR
        self.archive_dir = REVENUE_ARCHIVE_CACHE_DIR
        self.monthly_dir = REVENUE_MONTHLY_CACHE_DIR
        self.market_dirs = {"sii": REVENUE_CACHE_SII_DIR, "otc": REVENUE_CACHE_OTC_DIR}
        for folder in [
            self.cache_dir, self.raw_dir, self.normalized_dir, self.archive_dir, self.monthly_dir,
            REVENUE_CACHE_SII_DIR, REVENUE_CACHE_OTC_DIR, REVENUE_INDEX04_C04003_SII_DIR, REVENUE_MOPS_T21SC03_OTC_DIR,
            _r5n7d_revenue_pipeline_dir("raw", "sii", "index04_c04003"),
            _r5n7d_revenue_pipeline_dir("raw", "otc", "mops_t21sc03"),
            _r5n7d_revenue_pipeline_dir("normalized", "sii"),
            _r5n7d_revenue_pipeline_dir("normalized", "otc"),
            _r5n7d_revenue_pipeline_dir("archive", "sii"),
            _r5n7d_revenue_pipeline_dir("archive", "otc"),
        ]:
            folder.mkdir(parents=True, exist_ok=True)

    def monthly_cache_path(self, month: str, market_type: str | None = None) -> Path:
        m = RevenueAccelerationEngine.normalize_month(month)
        if not m:
            raise ValueError(f"invalid revenue month: {month}")
        mt = normalize_market_type(market_type)
        if mt in ("sii", "otc"):
            return self.market_dirs[mt] / f"revenue_{m}_{mt}.csv"
        return self.monthly_dir / f"revenue_{m}.csv"

    def normalized_cache_path(self, month: str, market_type: str | None = None) -> Path:
        m = RevenueAccelerationEngine.normalize_month(month)
        if not m:
            raise ValueError(f"invalid revenue month: {month}")
        mt = normalize_market_type(market_type)
        if mt in ("sii", "otc"):
            return _r5n7d_revenue_pipeline_dir("normalized", mt) / f"revenue_{m}_{mt}_normalized.csv"
        return self.normalized_dir / f"revenue_{m}_normalized.csv"

    def read_month_cache(self, month: str, market_type: str | None = None) -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(month)
        if not m:
            return pd.DataFrame()
        mt = normalize_market_type(market_type)
        paths = []
        if mt in ("sii", "otc"):
            paths = [self.monthly_cache_path(m, mt), self.normalized_cache_path(m, mt)]
        else:
            paths = [self.monthly_cache_path(m, "sii"), self.monthly_cache_path(m, "otc"), self.monthly_cache_path(m), self.normalized_cache_path(m)]
        parts = []
        for path in paths:
            try:
                if path.exists() and path.stat().st_size > 0:
                    df = safe_read_csv_auto(path)
                    if "revenue_month" in df.columns:
                        df["revenue_month"] = df["revenue_month"].map(RevenueAccelerationEngine.normalize_month)
                        df = df[df["revenue_month"].astype(str).eq(m)].copy()
                    if "market_type" not in df.columns:
                        df["market_type"] = mt if mt else normalize_market_type(path.name)
                    parts.append(df)
            except Exception as exc:
                log_warning(f"[RevenueCacheManager][READ_FAIL] month={m} market={mt or 'all'} path={path}｜{exc}")
        if not parts:
            return pd.DataFrame()
        return pd.concat(parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")

    def health_df(self, months: list[str]) -> pd.DataFrame:
        rows = []
        for month in months or []:
            m = RevenueAccelerationEngine.normalize_month(month)
            if not m:
                continue
            for mt, label in [("sii", "上市"), ("otc", "上櫃"), ("", "ALL")]:
                monthly_path = self.monthly_cache_path(m, mt or None)
                normalized_path = self.normalized_cache_path(m, mt or None)
                df = self.read_month_cache(m, mt or None)
                raw_dir = _r5n7d_revenue_pipeline_dir("raw", mt or None) if mt else REVENUE_RAW_CACHE_DIR
                archive_dir = _r5n7d_revenue_pipeline_dir("archive", mt or None) if mt else REVENUE_ARCHIVE_CACHE_DIR
                rows.append({
                    "月份": m,
                    "市場": label,
                    "market_type": mt or "all",
                    "MonthlyCache": str(monthly_path),
                    "MonthlyCache存在": "YES" if monthly_path.exists() and monthly_path.stat().st_size > 0 else "NO",
                    "NormalizedCache": str(normalized_path),
                    "NormalizedCache存在": "YES" if normalized_path.exists() and normalized_path.stat().st_size > 0 else "NO",
                    "RawDir": str(raw_dir),
                    "Raw檔案數": len(list(raw_dir.rglob("*"))) if raw_dir.exists() else 0,
                    "ArchiveDir": str(archive_dir),
                    "Archive檔案數": len(list(archive_dir.rglob("*"))) if archive_dir.exists() else 0,
                    "Manifest": str(_r5n7d_manifest_path()),
                    "Manifest存在": "YES" if _r5n7d_manifest_path().exists() else "NO",
                    "Cache有效筆數": int(len(df)) if df is not None else 0,
                    "Cache驗收": "PASS" if df is not None and len(df) > 0 else "FAIL",
                })
        return pd.DataFrame(rows)


class RevenueHybridCoveragePolicy:
    """R5N5_FINAL：Hybrid 覆蓋規則集中定義。

    優先順序：DB正式表 > DB即時公告表 > 本機逐月Cache > 重新下載官方來源。
    正式 TWSE/TPEx 月報覆蓋即時公告，但不得覆蓋既有有效 history 值。
    """

    PRIORITY_TEXT = "DB:external_revenue_history > DB:external_revenue_announce > Cache:revenue_YYYYMM.csv > OfficialDownload"

    @staticmethod
    def describe() -> pd.DataFrame:
        return pd.DataFrame([
            {"順序": 1, "來源": "external_revenue_history", "規則": "正式月報首選；已有有效 revenue 時不得被即時/Cache 覆蓋"},
            {"順序": 2, "來源": "external_revenue_announce", "規則": "6/1~6/10 即時公告追蹤；只補正式月報尚未出現的 stock_id+month"},
            {"順序": 3, "來源": "RevenueCacheManager", "規則": "讀本機逐月 cache；cache 月份必須等於 required_month，不可用最新月假補"},
            {"順序": 4, "來源": "OfficialDownload", "規則": "Cache/DB 缺月時才抓 TWSE Index04 / MOPS t21sc04 / OpenAPI"},
            {"順序": 5, "來源": "Completeness Gate", "規則": "202602/202603/202604 全月 PASS 才允許正式EPS+營收雙驗證"},
        ])


class RevenueCompletenessValidator:
    """R5N5_FINAL：營收完整性驗證器。

    預設驗證 202602 / 202603 / 202604，對應使用者要求的 R5L 全部 PASS。
    產出供 Excel 01F_營收完整性驗證 Sheet 與 DB revenue_completeness_check 使用。
    """

    DEFAULT_REQUIRED_MONTHS = ["202602", "202603", "202604"]

    def __init__(self, db: DBManager, cache_manager: RevenueCacheManager | None = None):
        self.db = db
        self.cache_manager = cache_manager or RevenueCacheManager(REVENUE_CACHE_DIR)

    def _read_master(self) -> pd.DataFrame:
        try:
            with self.db.lock:
                df = pd.read_sql_query("SELECT stock_id, stock_name, market, is_etf FROM stocks_master WHERE is_active=1", self.db.conn)
            return _r5n7d_exclude_non_revenue_universe(df)
        except Exception:
            return pd.DataFrame(columns=["stock_id", "stock_name", "market", "is_etf"])

    def _read_revenue_source(self, table: str, months: list[str]) -> pd.DataFrame:
        try:
            with self.db.lock:
                exists = self.db.conn.cursor().execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone()
                if not exists:
                    return pd.DataFrame()
                placeholders = ",".join(["?"] * len(months))
                return pd.read_sql_query(
                    f"SELECT stock_id, revenue_month, COALESCE(market_type,'') AS market_type, revenue, yoy, source_date, update_time FROM {table} WHERE revenue_month IN ({placeholders})",
                    self.db.conn,
                    params=months,
                )
        except Exception as exc:
            log_warning(f"[RevenueCompletenessValidator][READ_FAIL] table={table}｜{exc}")
            return pd.DataFrame()

    def validate(self, required_months: list[str] | None = None, persist: bool = True) -> pd.DataFrame:
        months = [RevenueAccelerationEngine.normalize_month(m) for m in (required_months or self.DEFAULT_REQUIRED_MONTHS)]
        months = [m for m in months if m]
        master = self._read_master()
        if master is None or master.empty:
            master = pd.DataFrame(columns=["stock_id", "stock_name"])
        master["stock_id"] = master.get("stock_id", "").map(normalize_stock_id)
        master = master[master["stock_id"].astype(str).ne("")].drop_duplicates("stock_id")

        source_parts = []
        for table, source_name in [("external_revenue_history", "正式月報"), ("external_revenue_announce", "即時公告")]:
            part = self._read_revenue_source(table, months)
            if part is not None and not part.empty:
                part["stock_id"] = part["stock_id"].map(normalize_stock_id)
                part["revenue_month"] = part["revenue_month"].map(RevenueAccelerationEngine.normalize_month)
                part["revenue"] = pd.to_numeric(part.get("revenue"), errors="coerce")
                part["source_priority"] = source_name
                source_parts.append(part)
        revenue = pd.concat(source_parts, ignore_index=True) if source_parts else pd.DataFrame(columns=["stock_id", "revenue_month", "revenue", "source_priority"])
        if not revenue.empty:
            revenue = revenue[pd.to_numeric(revenue.get("revenue"), errors="coerce").fillna(0).gt(0)].copy()
            revenue = revenue.sort_values(["stock_id", "revenue_month", "source_priority"], ascending=[True, True, True])
            revenue = revenue.drop_duplicates(["stock_id", "revenue_month"], keep="first")

        # 若 DB 沒有資料，至少用 cache 做月別層驗證；不把 cache 股票清單寫成正式通過，但能顯示缺口來源。
        cache_health = self.cache_manager.health_df(months)
        rows = []
        for _, r in master.iterrows():
            sid = normalize_stock_id(r.get("stock_id"))
            sname = str(r.get("stock_name", ""))
            hit = sorted(revenue.loc[revenue["stock_id"].astype(str).eq(sid), "revenue_month"].dropna().astype(str).unique().tolist()) if not revenue.empty else []
            missing = [m for m in months if m not in hit]
            pass_flag = len(missing) == 0 and len(months) > 0
            rows.append({
                "stock_id": sid,
                "stock_name": sname,
                "required_months": ",".join(months),
                "hit_months": ",".join(hit),
                "missing_months": ",".join(missing),
                "202602": "PASS" if "202602" in hit else ("N/A" if "202602" not in months else "FAIL"),
                "202603": "PASS" if "202603" in hit else ("N/A" if "202603" not in months else "FAIL"),
                "202604": "PASS" if "202604" in hit else ("N/A" if "202604" not in months else "FAIL"),
                "pass_flag": int(pass_flag),
                "pass_status": "PASS" if pass_flag else "FAIL",
                "source_priority": RevenueHybridCoveragePolicy.PRIORITY_TEXT,
                "cache_month_pass_count": int(cache_health[cache_health["Cache驗收"].eq("PASS")]["月份"].nunique()) if not cache_health.empty else 0,
                "update_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            })
        out = pd.DataFrame(rows)
        if out.empty:
            out = pd.DataFrame([{
                "stock_id": "", "stock_name": "NO_MASTER", "required_months": ",".join(months),
                "hit_months": "", "missing_months": ",".join(months),
                "202602": "FAIL", "202603": "FAIL", "202604": "FAIL",
                "pass_flag": 0, "pass_status": "FAIL", "source_priority": RevenueHybridCoveragePolicy.PRIORITY_TEXT,
                "cache_month_pass_count": 0, "update_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            }])
        if persist and not out.empty:
            self.persist(out)
        return out

    def persist(self, df: pd.DataFrame) -> int:
        if df is None or df.empty:
            return 0
        check_date = datetime.now().strftime("%Y-%m-%d")
        rows = []
        for _, r in df.iterrows():
            rows.append((
                check_date, str(r.get("stock_id", "")), str(r.get("stock_name", "")),
                str(r.get("required_months", "")), str(r.get("hit_months", "")), str(r.get("missing_months", "")),
                int(r.get("pass_flag", 0) or 0), str(r.get("pass_status", "")), str(r.get("source_priority", "")),
                str(r.get("update_time", datetime.now().strftime("%Y-%m-%d %H:%M:%S"))),
            ))
        sql = """
            INSERT INTO revenue_completeness_check(
                check_date,stock_id,stock_name,required_months,hit_months,missing_months,pass_flag,pass_status,source_priority,update_time
            ) VALUES(?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(check_date, stock_id, required_months) DO UPDATE SET
                stock_name=excluded.stock_name,
                hit_months=excluded.hit_months,
                missing_months=excluded.missing_months,
                pass_flag=excluded.pass_flag,
                pass_status=excluded.pass_status,
                source_priority=excluded.source_priority,
                update_time=excluded.update_time
        """
        try:
            with self.db.lock:
                self.db.conn.cursor().executemany(sql, rows)
                self.db.conn.commit()
            return len(rows)
        except Exception as exc:
            log_warning(f"[RevenueCompletenessValidator][PERSIST_FAIL] {exc}")
            return 0


class R5N6FinalSafeIntegrator:
    """R5N6_FINAL_SAFE_PATCH：安全補齊 EPS cache 與上櫃營收缺月。

    來源：R5N6_FINAL_SAFE_PATCH_20260611.py 整合版。
    重點：
    - 不使用假的 tpex.org.tw / twse.com.tw 網域首頁當資料 API。
    - 上櫃營收先讀本機逐月 cache，再由 TPEx swagger 動態發現營收 endpoint，最後才用 MOPS ajax fallback。
    - 所有遠端資料必須欄位可辨識且月份吻合才寫入 external_revenue_history。
    - DB 寫入採 append/repair：不覆蓋既有有效 revenue。
    """

    TPEX_REVENUE_CANDIDATE_URLS = [
        "https://www.tpex.org.tw/openapi/v1/mopsfin_t187ap15_O",
        "https://www.tpex.org.tw/openapi/v1/mopsfin_t187ap05_O",
        "https://www.tpex.org.tw/openapi/v1/tpex_mainboard_monthly_revenue",
    ]
    MOPS_REVENUE_FALLBACK_URLS = [
        "https://mops.twse.com.tw/mops/web/ajax_t21sc04",
        "https://mopsov.twse.com.tw/mops/web/ajax_t21sc04",
        "https://mops.twse.com.tw/mops/web/t05st10_ifrs",
    ]

    def __init__(self, db: DBManager, cache_dir: Path | None = None):
        self.db = db
        self.cache_dir = Path(cache_dir or REVENUE_CACHE_DIR)
        self.cache_dirs = [
            self.cache_dir,
            self.cache_dir / "raw",
            self.cache_dir / "normalized",
            self.cache_dir / "archive",
            RUNTIME_DIR / "data" / "official_revenue_openapi",
            RUNTIME_DIR / "revenue_cache",
        ]
        self.actual_q1_eps_cache: dict[str, float] = {}

    @staticmethod
    def _safe_float(value, default=np.nan):
        try:
            if value is None:
                return default
            s = str(value).strip().replace(',', '').replace('--', '')
            if s in ('', '-', 'None', 'nan', 'NaN', '<NA>', 'NULL', 'null'):
                return default
            v = pd.to_numeric(s, errors='coerce')
            return float(v) if pd.notna(v) else default
        except Exception:
            return default

    @staticmethod
    def _safe_revenue(value):
        v = R5N6FinalSafeIntegrator._safe_float(value, default=np.nan)
        if not np.isfinite(v):
            return np.nan
        return float(v)

    @staticmethod
    def _norm_col_name(name) -> str:
        return re.sub(r"[\s\(\)（）％%]", "", str(name or ""))

    @classmethod
    def _find_col(cls, df: pd.DataFrame, candidates: list[str]) -> str | None:
        if df is None or df.empty:
            return None
        cols = list(df.columns)
        exact = {cls._norm_col_name(c): c for c in cols}
        for cand in candidates:
            key = cls._norm_col_name(cand)
            if key in exact:
                return exact[key]
        for c in cols:
            n = cls._norm_col_name(c)
            for cand in candidates:
                if cls._norm_col_name(cand) in n:
                    return c
        return None

    @staticmethod
    def _flatten_df(df: pd.DataFrame) -> pd.DataFrame:
        x = df.copy()
        if isinstance(x.columns, pd.MultiIndex):
            x.columns = ["_".join([str(v).strip() for v in tup if str(v).strip() and not str(v).lower().startswith('unnamed')]) for tup in x.columns]
        else:
            x.columns = [str(c).strip() for c in x.columns]
        if not x.empty:
            first_values = [str(v).strip() for v in x.iloc[0].tolist()]
            if "公司代號" in first_values or "公司名稱" in first_values:
                x.columns = _coerce_unique_columns(first_values)
                x = x.iloc[1:].reset_index(drop=True)
        x.columns = [str(c).replace('\n', '').replace('\r', '').strip() for c in x.columns]
        return x

    def _ensure_schema(self):
        try:
            with self.db.lock:
                cur = self.db.conn.cursor()
                for ddl in [
                    "ALTER TABLE external_revenue_history ADD COLUMN source_type TEXT",
                    "ALTER TABLE financial_feature_daily ADD COLUMN actual_q1_eps REAL",
                    "ALTER TABLE financial_feature_daily ADD COLUMN actual_q1_eps_source_type TEXT",
                    "ALTER TABLE financial_feature_daily ADD COLUMN actual_q1_eps_market_type TEXT",
                    "ALTER TABLE financial_feature_daily ADD COLUMN actual_q1_eps_update_time TEXT",
                ]:
                    try:
                        cur.execute(ddl)
                    except Exception:
                        pass
                self.db.conn.commit()
        except Exception as exc:
            log_warning(f"[R5N6_SAFE][SCHEMA] skipped｜{exc}")

    def normalize_revenue_df(self, df: pd.DataFrame, revenue_month: str, source_type: str, source_url: str = "") -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(revenue_month)
        if df is None or df.empty or not m:
            return pd.DataFrame()
        x = self._flatten_df(df).fillna("")
        id_col = self._find_col(x, ["公司代號", "公司代碼", "股票代號", "證券代號", "SecuritiesCompanyCode", "stock_id", "Code"])
        rev_col = self._find_col(x, ["當月營收", "本月營收", "營業收入-當月營收", "CurrentMonthRevenue", "monthly_revenue", "revenue"])
        month_col = self._find_col(x, ["出表年月", "資料年月", "營收年月", "年月", "RevenueMonth", "revenue_month", "YearMonth"])
        last_col = self._find_col(x, ["上月營收", "LastMonthRevenue"])
        last_year_col = self._find_col(x, ["去年當月營收", "去年同月營收", "LastYearSameMonthRevenue"])
        yoy_col = self._find_col(x, ["前期比較增減(%)", "去年同月增減(%)", "營業收入-去年同月增減(%)", "CurrentMonthRevenueYoY", "yoy"])
        mom_col = self._find_col(x, ["上月比較增減(%)", "CurrentMonthRevenueMoM", "mom"])
        cum_col = self._find_col(x, ["累計營收", "累計營業收入-當月累計營收", "cumulative_revenue"])
        cum_yoy_col = self._find_col(x, ["累計增減(%)", "累計營業收入-前期比較增減(%)", "cumulative_yoy"])
        if id_col is None or rev_col is None:
            return pd.DataFrame()
        if month_col is not None:
            mm = x[month_col].map(RevenueAccelerationEngine.normalize_month)
            x = x[mm.astype(str).eq(m)].copy()
            if x.empty:
                return pd.DataFrame()
        rows = []
        for _, r in x.iterrows():
            sid = normalize_stock_id(r.get(id_col, ""))
            revenue = self._safe_revenue(r.get(rev_col, np.nan))
            if not sid or not np.isfinite(revenue) or revenue <= 0:
                continue
            yoy = self._safe_float(r.get(yoy_col, np.nan), default=np.nan) if yoy_col is not None else np.nan
            mom = self._safe_float(r.get(mom_col, np.nan), default=np.nan) if mom_col is not None else np.nan
            if (not np.isfinite(yoy)) and last_year_col is not None:
                last_year_rev = self._safe_float(r.get(last_year_col, np.nan), default=np.nan)
                if np.isfinite(last_year_rev) and last_year_rev != 0:
                    yoy = round((revenue - last_year_rev) / abs(last_year_rev) * 100.0, 4)
            if (not np.isfinite(mom)) and last_col is not None:
                last_rev = self._safe_float(r.get(last_col, np.nan), default=np.nan)
                if np.isfinite(last_rev) and last_rev != 0:
                    mom = round((revenue - last_rev) / abs(last_rev) * 100.0, 4)
            cumulative_revenue = self._safe_float(r.get(cum_col, np.nan), default=np.nan) if cum_col is not None else np.nan
            cumulative_yoy = self._safe_float(r.get(cum_yoy_col, np.nan), default=np.nan) if cum_yoy_col is not None else np.nan
            rows.append({
                "stock_id": sid,
                "revenue_month": m,
                "revenue": float(revenue),
                "mom": mom if np.isfinite(mom) else np.nan,
                "yoy": yoy if np.isfinite(yoy) else np.nan,
                "cumulative_revenue": cumulative_revenue if np.isfinite(cumulative_revenue) else np.nan,
                "cumulative_yoy": cumulative_yoy if np.isfinite(cumulative_yoy) else np.nan,
                "source_url": source_url,
                "source_date": f"{m[:4]}-{m[4:6]}",
                "source_type": source_type,
                "update_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            })
        return pd.DataFrame(rows).drop_duplicates(["stock_id", "revenue_month"], keep="last") if rows else pd.DataFrame()

    def _read_any_table_file(self, path: Path) -> pd.DataFrame:
        if path.suffix.lower() == ".json":
            raw = json.loads(path.read_text(encoding="utf-8-sig"))
            if isinstance(raw, dict):
                raw = raw.get("data") or raw.get("records") or raw.get("result") or []
            return pd.DataFrame(raw)
        if path.suffix.lower() in (".csv", ".txt"):
            return safe_read_csv_auto(path)
        if path.suffix.lower() in (".xlsx", ".xls"):
            return safe_read_excel(path)
        return pd.DataFrame()

    def read_local_revenue_cache(self, revenue_month: str) -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(revenue_month)
        if not m:
            return pd.DataFrame()
        files = []
        for d in self.cache_dirs:
            try:
                if not Path(d).exists():
                    continue
                for pat in [f"*{m}*上櫃*.json", f"*{m}*otc*.json", f"*{m}*.json", f"*{m}*上櫃*.csv", f"*{m}*otc*.csv", f"revenue_{m}.csv", f"*{m}*.xlsx"]:
                    files.extend(Path(x) for x in Path(d).glob(pat) if not str(x).endswith(".meta.json"))
            except Exception:
                continue
        parts = []
        for f in sorted(set(files)):
            try:
                raw = self._read_any_table_file(f)
                parsed = self.normalize_revenue_df(raw, m, source_type=f"LOCAL_REVENUE_CACHE:{f.name}", source_url=str(f))
                if parsed is not None and not parsed.empty:
                    parts.append(parsed)
            except Exception as exc:
                log_warning(f"[R5N6_SAFE][LOCAL_REVENUE_PARSE_FAIL] file={f}｜{exc}")
        if parts:
            out = pd.concat(parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")
            log_info(f"[R5N6_SAFE][LOCAL_REVENUE_OK] month={m} rows={len(out)}")
            return out
        return pd.DataFrame()

    def discover_tpex_revenue_urls(self) -> list[str]:
        urls = []
        try:
            resp = requests.get(TPEX_OPENAPI_SWAGGER_URL, timeout=15, headers={"User-Agent": "Mozilla/5.0", "Accept": "application/json"})
            if resp.status_code == 200:
                spec = resp.json()
                paths = spec.get("paths", {}) if isinstance(spec, dict) else {}
                keywords = ("營收", "營業收入", "revenue", "t187ap05", "t187ap15", "monthly")
                for p, ops in paths.items():
                    hay = (str(p) + " " + json.dumps(ops, ensure_ascii=False)).lower()
                    if any(k.lower() in hay for k in keywords):
                        urls.append(p if str(p).startswith("http") else "https://www.tpex.org.tw" + str(p))
        except Exception as exc:
            log_warning(f"[R5N6_SAFE][TPEX_SWAGGER_DISCOVERY_FAIL] {exc}")
        for url in list(REVENUE_OPENAPI_ENDPOINTS.values()) + list(REVENUE_OPENAPI_OPTIONAL_ENDPOINTS.values()) + self.TPEX_REVENUE_CANDIDATE_URLS:
            if "tpex.org.tw" in str(url) and url not in urls:
                urls.append(url)
        return urls

    def fetch_tpex_revenue(self, revenue_month: str) -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(revenue_month)
        if not m:
            return pd.DataFrame()
        for url in self.discover_tpex_revenue_urls():
            try:
                resp = requests.get(url, timeout=30, headers={"User-Agent": "Mozilla/5.0", "Accept": "application/json,text/plain,*/*", "Referer": "https://www.tpex.org.tw/openapi/"})
                if resp.status_code != 200 or not str(resp.text or "").strip():
                    continue
                payload = resp.json()
                if isinstance(payload, dict):
                    payload = payload.get("data") or payload.get("records") or payload.get("result") or []
                if not isinstance(payload, list):
                    continue
                parsed = self.normalize_revenue_df(pd.DataFrame(payload), m, source_type=f"TPEX_OPENAPI:{url}", source_url=url)
                if parsed is not None and not parsed.empty:
                    log_info(f"[R5N6_SAFE][TPEX_REVENUE_OK] month={m} url={url} rows={len(parsed)}")
                    return parsed
            except Exception as exc:
                log_warning(f"[R5N6_SAFE][TPEX_REVENUE_CANDIDATE_FAIL] url={url}｜{exc}")
        return pd.DataFrame()

    def fetch_mops_revenue_fallback(self, revenue_month: str) -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(revenue_month)
        if not m:
            return pd.DataFrame()
        year = int(m[:4]); month = int(m[4:6]); roc_year = year - 1911
        payloads = [
            {"encodeURIComponent": "1", "step": "1", "firstin": "1", "TYPEK": "otc", "year": str(roc_year), "month": f"{month:02d}", "co_id": ""},
            {"step": "1", "TYPEK": "otc", "year": str(roc_year), "month": f"{month:02d}", "co_id": ""},
        ]
        headers = {"User-Agent": "Mozilla/5.0", "Accept": "text/html,*/*", "Referer": "https://mops.twse.com.tw/mops/web/t21sc04"}
        for url in self.MOPS_REVENUE_FALLBACK_URLS:
            for payload in payloads:
                try:
                    resp = requests.post(url, data=payload, timeout=30, headers=headers)
                    resp.encoding = "utf-8"
                    if resp.status_code != 200 or "公司代號" not in str(resp.text or ""):
                        continue
                    tables = pd.read_html(io.StringIO(resp.text))
                    frames = []
                    for table in tables:
                        parsed = self.normalize_revenue_df(table, m, source_type=f"MOPS_FALLBACK:{url}", source_url=url)
                        if parsed is not None and not parsed.empty:
                            frames.append(parsed)
                    if frames:
                        out = pd.concat(frames, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")
                        log_info(f"[R5N6_SAFE][MOPS_REVENUE_OK] month={m} url={url} rows={len(out)}")
                        return out
                except Exception as exc:
                    log_warning(f"[R5N6_SAFE][MOPS_REVENUE_FAIL] url={url}｜{exc}")
        return pd.DataFrame()

    def fetch_revenue_strict(self, revenue_month: str) -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(revenue_month)
        if not m:
            return pd.DataFrame()
        for getter, source_name in [
            (self.read_local_revenue_cache, "LOCAL_CACHE"),
            (self.fetch_tpex_revenue, "TPEX_OPENAPI"),
            (self.fetch_mops_revenue_fallback, "MOPS_FALLBACK"),
        ]:
            df = getter(m)
            if df is not None and not df.empty and df["revenue_month"].astype(str).eq(m).all():
                return df
            if df is not None and not df.empty:
                log_warning(f"[R5N6_SAFE][MONTH_MISMATCH_REJECT] month={m} source={source_name} rows={len(df)}")
        return pd.DataFrame()

    def upsert_revenue_history(self, df: pd.DataFrame) -> int:
        if df is None or df.empty:
            return 0
        self._ensure_schema()
        rows = []
        for _, r in df.iterrows():
            rows.append((
                normalize_stock_id(r.get("stock_id")), str(r.get("revenue_month")), float(r.get("revenue")),
                self._safe_float(r.get("mom"), default=np.nan), self._safe_float(r.get("yoy"), default=np.nan),
                self._safe_float(r.get("cumulative_revenue"), default=np.nan), self._safe_float(r.get("cumulative_yoy"), default=np.nan),
                str(r.get("source_url", "")), str(r.get("source_date", "")), str(r.get("source_type", "")),
                str(r.get("update_time", datetime.now().strftime("%Y-%m-%d %H:%M:%S"))),
            ))
        sql = """
            INSERT INTO external_revenue_history(stock_id,revenue_month,revenue,mom,yoy,cumulative_revenue,cumulative_yoy,source_url,source_date,source_type,update_time)
            VALUES(?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(stock_id, revenue_month) DO UPDATE SET
                market_type=CASE WHEN COALESCE(external_revenue_history.market_type,'')='' THEN excluded.market_type ELSE external_revenue_history.market_type END,
                revenue=CASE WHEN COALESCE(external_revenue_history.revenue,0)<=0 THEN excluded.revenue ELSE external_revenue_history.revenue END,
                mom=CASE WHEN external_revenue_history.mom IS NULL THEN excluded.mom ELSE external_revenue_history.mom END,
                yoy=CASE WHEN external_revenue_history.yoy IS NULL THEN excluded.yoy ELSE external_revenue_history.yoy END,
                cumulative_revenue=CASE WHEN external_revenue_history.cumulative_revenue IS NULL THEN excluded.cumulative_revenue ELSE external_revenue_history.cumulative_revenue END,
                cumulative_yoy=CASE WHEN external_revenue_history.cumulative_yoy IS NULL THEN excluded.cumulative_yoy ELSE external_revenue_history.cumulative_yoy END,
                source_url=CASE WHEN COALESCE(external_revenue_history.source_url,'')='' THEN excluded.source_url ELSE external_revenue_history.source_url END,
                source_date=CASE WHEN COALESCE(external_revenue_history.source_date,'')='' THEN excluded.source_date ELSE external_revenue_history.source_date END,
                source_type=CASE WHEN COALESCE(external_revenue_history.source_type,'')='' THEN excluded.source_type ELSE external_revenue_history.source_type END,
                update_time=excluded.update_time
        """
        try:
            with self.db.lock:
                self.db.conn.cursor().executemany(sql, rows)
                self.db.conn.commit()
            return len(rows)
        except Exception as exc:
            log_warning(f"[R5N6_SAFE][REVENUE_UPSERT_FAIL] {exc}")
            return 0

    def patch_missing_revenue_months(self, months: list[str]) -> pd.DataFrame:
        summary = []
        self._ensure_schema()
        for raw_m in months or []:
            m = RevenueAccelerationEngine.normalize_month(raw_m)
            if not m:
                continue
            before = 0
            try:
                with self.db.lock:
                    row = self.db.conn.cursor().execute("SELECT COUNT(*) FROM external_revenue_history WHERE revenue_month=? AND COALESCE(revenue,0)>0", (m,)).fetchone()
                    before = int(row[0] or 0) if row else 0
            except Exception:
                before = 0
            df = self.fetch_revenue_strict(m)
            written = self.upsert_revenue_history(df)
            after = before
            try:
                with self.db.lock:
                    row = self.db.conn.cursor().execute("SELECT COUNT(*) FROM external_revenue_history WHERE revenue_month=? AND COALESCE(revenue,0)>0", (m,)).fetchone()
                    after = int(row[0] or 0) if row else before
            except Exception:
                pass
            summary.append({
                "月份": m,
                "SAFE_PATCH狀態": "PASS" if after > 0 else "FAIL",
                "補丁前DB筆數": before,
                "本次候選筆數": int(len(df)) if df is not None else 0,
                "本次寫入嘗試筆數": written,
                "補丁後DB筆數": after,
                "來源": str(df.get("source_type", pd.Series([""])).iloc[0]) if df is not None and not df.empty and "source_type" in df.columns else "",
                "說明": "只接受月份吻合且欄位可辨識資料；不使用網域首頁假API" if after > 0 else "未找到可驗證資料，未寫入避免污染DB",
            })
        return pd.DataFrame(summary)

    def sync_actual_q1_eps_cache(self, fiscal_year: int, feature_date: str | None = None) -> pd.DataFrame:
        self._ensure_schema()
        feature_date = feature_date or datetime.now().strftime("%Y-%m-%d")
        rows = []
        try:
            with self.db.lock:
                src = pd.read_sql_query("""
                    SELECT stock_id, eps_quarter AS actual_q1_eps, COALESCE(source_type,'') AS source_type
                    FROM quarterly_financial_history
                    WHERE fiscal_year=? AND quarter=1 AND eps_quarter IS NOT NULL
                """, self.db.conn, params=[int(fiscal_year)])
                if src is None or src.empty:
                    return pd.DataFrame([{"項目": "actual_q1_eps_cache", "狀態": "FAIL", "筆數": 0, "說明": f"quarterly_financial_history 無 {fiscal_year}Q1 eps_quarter"}])
                now = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                tuples = []
                for _, r in src.iterrows():
                    sid = normalize_stock_id(r.get("stock_id"))
                    val = pd.to_numeric(r.get("actual_q1_eps"), errors="coerce")
                    if sid and pd.notna(val):
                        tuples.append((sid, feature_date, float(val), str(r.get("source_type") or ""), now))
                        self.actual_q1_eps_cache[sid] = float(val)
                self.db.conn.cursor().executemany("""
                    INSERT INTO financial_feature_daily(stock_id, feature_date, actual_q1_eps, actual_q1_eps_source_type, actual_q1_eps_market_type, actual_q1_eps_update_time, update_time)
                    VALUES(?,?,?,?,?,?,?)
                    ON CONFLICT(stock_id, feature_date) DO UPDATE SET
                        actual_q1_eps=excluded.actual_q1_eps,
                        actual_q1_eps_source_type=excluded.actual_q1_eps_source_type,
                        actual_q1_eps_market_type=excluded.actual_q1_eps_market_type,
                        actual_q1_eps_update_time=excluded.actual_q1_eps_update_time,
                        update_time=excluded.update_time
                """, tuples)
                self.db.conn.commit()
                rows.append({"項目": "actual_q1_eps_cache", "狀態": "PASS", "筆數": len(tuples), "說明": "由 quarterly_financial_history 回填 financial_feature_daily"})
        except Exception as exc:
            rows.append({"項目": "actual_q1_eps_cache", "狀態": "FAIL", "筆數": 0, "說明": str(exc)})
        return pd.DataFrame(rows)

    def run(self, required_months: list[str], fiscal_year: int, feature_date: str | None = None) -> pd.DataFrame:
        parts = []
        try:
            parts.append(self.patch_missing_revenue_months(required_months))
        except Exception as exc:
            parts.append(pd.DataFrame([{"月份": "ALL", "SAFE_PATCH狀態": "FAIL", "說明": f"patch_missing_revenue_months exception: {exc}"}]))
        try:
            eps_sync = self.sync_actual_q1_eps_cache(fiscal_year, feature_date=feature_date)
            if eps_sync is not None and not eps_sync.empty:
                eps_sync = eps_sync.rename(columns={"項目": "月份", "狀態": "SAFE_PATCH狀態", "筆數": "本次寫入嘗試筆數", "說明": "說明"})
                parts.append(eps_sync)
        except Exception as exc:
            parts.append(pd.DataFrame([{"月份": "actual_q1_eps_cache", "SAFE_PATCH狀態": "FAIL", "說明": str(exc)}]))
        return pd.concat([p for p in parts if p is not None and not p.empty], ignore_index=True, sort=False) if parts else pd.DataFrame()


class RevenueOpenAPICacheDownloader:
    """R4A：官方月營收 OpenAPI 快取下載器（append-only repair layer）。

    定位：
    - 不取代 R4 原本 fetch_revenue / writer / history fallback。
    - 僅在原流程缺月份或官方抓取失敗時，補讀/補抓官方 OpenAPI 快取。
    - 寫入 history 時必須由呼叫端使用 INSERT OR IGNORE / append-only，禁止覆蓋既有有效資料。
    """

    def __init__(self, cache_dir: Path | None = None, trace_engine=None):
        self.cache_dir = Path(cache_dir or REVENUE_CACHE_DIR)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.monthly_cache_dir = Path(REVENUE_MONTHLY_CACHE_DIR)
        self.monthly_cache_dir.mkdir(parents=True, exist_ok=True)
        self.trace_engine = trace_engine
        self.endpoints = dict(REVENUE_OPENAPI_ENDPOINTS)
        self.optional_endpoints = dict(REVENUE_OPENAPI_OPTIONAL_ENDPOINTS)

    @staticmethod
    def _num(v, default: float = np.nan) -> float:
        try:
            s = str(v).replace(',', '').replace('--', '').strip()
            if s in ('', '-', 'None', 'nan', 'NaN', '<NA>'):
                return float(default)
            return float(s)
        except Exception:
            return float(default)

    @staticmethod
    def _find_revenue_columns(raw: pd.DataFrame) -> dict:
        col_map = {}
        if raw is None or raw.empty:
            return col_map
        for c in raw.columns:
            cs = str(c).strip()
            if cs in ("公司代號", "公司代碼", "股票代號", "證券代號", "SecuritiesCompanyCode", "Code"):
                col_map.setdefault("stock_id", c)
            elif (cs in ("出表年月", "出表日期", "資料年月", "年月", "營收年月", "營業收入年月", "月份", "RevenueMonth", "YearMonth", "month", "Month")
                  or ("資料年月" in cs) or ("營收年月" in cs) or ("出表年月" in cs)):
                col_map.setdefault("revenue_month", c)
            elif (("當月營收" in cs) or ("本月營收" in cs) or cs in ("營業收入-當月營收", "營收", "revenue", "Revenue")):
                if "累計" not in cs and "去年" not in cs and "增減" not in cs:
                    col_map.setdefault("revenue", c)
            elif ("上月" in cs and "增減" in cs) or ("MoM" in cs) or ("mom" == cs.lower()):
                col_map.setdefault("mom", c)
            elif ((("去年" in cs or "同期" in cs or "YoY" in cs or "yoy" == cs.lower()) and "增減" in cs)
                  or cs in ("營業收入-去年同月增減(%)", "去年同月增減(%)")):
                col_map.setdefault("yoy", c)
            elif (("累計" in cs and "營收" in cs and "增減" not in cs) or cs in ("累計營業收入-當月累計營收", "累計營收")):
                col_map.setdefault("cumulative_revenue", c)
            elif ("累計" in cs and "增減" in cs) or cs in ("累計營業收入-前期比較增減(%)", "累計增減(%)"):
                col_map.setdefault("cumulative_yoy", c)
        return col_map

    def cache_path_for_month(self, month: str) -> Path:
        m = RevenueAccelerationEngine.normalize_month(month)
        if not m:
            raise ValueError(f"invalid revenue month: {month}")
        return self.monthly_cache_dir / f"revenue_{m}.csv"

    def _emit_cache_trace(self, month: str, stage: str, status: str, rows: int = 0, cache_path: Path | None = None, reason_code: str = "", reason_detail: str = ""):
        try:
            if self.trace_engine is not None:
                self.trace_engine.event(
                    module="Revenue",
                    source_name="RevenueMonthlyCache",
                    stage=stage,
                    status=status,
                    target_table="external_revenue_history",
                    source_file=str(cache_path or ""),
                    rows_downloaded=rows,
                    rows_parsed=rows,
                    rows_written=rows if str(status).upper() == "PASS" and stage == "CACHE_WRITE" else 0,
                    verify_count=rows if stage == "CACHE_VERIFY" else 0,
                    fail_reason_code=reason_code,
                    fail_reason_detail=reason_detail,
                    source_date=str(month or ""),
                )
            else:
                log_info(f"[EXTERNAL_TRACE][R5L_CACHE] month={month} stage={stage} status={status} rows={rows} file={cache_path} reason={reason_code} detail={reason_detail}")
        except Exception as exc:
            log_warning(f"[R5L][CACHE_TRACE][SKIP] month={month} stage={stage}｜{exc}")

    def _normalize_month_cache_df(self, df: pd.DataFrame, month: str, source_url: str = "") -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(month)
        if df is None or df.empty or not m:
            return pd.DataFrame()
        x = df.copy().fillna("")
        if "stock_id" not in x.columns or "revenue" not in x.columns:
            return pd.DataFrame()
        if "revenue_month" not in x.columns:
            x["revenue_month"] = m
        x["stock_id"] = x["stock_id"].map(normalize_stock_id)
        x["revenue_month"] = x["revenue_month"].map(RevenueAccelerationEngine.normalize_month).fillna("").astype(str)
        for c in ["revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy"]:
            if c not in x.columns:
                x[c] = np.nan
            x[c] = pd.to_numeric(x[c], errors="coerce")
        if "source_date" not in x.columns:
            x["source_date"] = f"{m[:4]}-{m[4:6]}"
        if "source_url" not in x.columns:
            x["source_url"] = source_url
        if "market_type" not in x.columns:
            x["market_type"] = normalize_market_type(source_url)
        x["market_type"] = x["market_type"].map(normalize_market_type)
        if "update_time" not in x.columns:
            x["update_time"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        x = x[(x["stock_id"].astype(str).ne("")) & x["revenue_month"].eq(m) & (x["revenue"] > 0)].copy()
        if x.empty:
            return pd.DataFrame()
        keep = ["stock_id", "revenue_month", "market_type", "revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy", "source_date", "source_url", "update_time"]
        return x[keep].drop_duplicates(["stock_id", "revenue_month"], keep="last")

    def write_month_cache(self, df: pd.DataFrame, month: str, source_url: str = "") -> Path | None:
        """R5N7D：統一月營收 cache 寫入。

        寫入規則：
        1. root revenue_YYYYMM.csv 僅保留舊版相容 all cache。
        2. final cache 一律分流到 sii/otc/revenue_YYYYMM_market.csv。
        3. normalized cache 一律分流到 normalized/sii|otc。
        4. 覆蓋前先複製到 archive，並寫 data_pipeline_manifest.json。
        """
        m = RevenueAccelerationEngine.normalize_month(month)
        if not m:
            return None
        cache_path = self.cache_path_for_month(m)
        x = self._normalize_month_cache_df(df, m, source_url=source_url)
        if x.empty:
            self._emit_cache_trace(m, "CACHE_WRITE", "FAIL", 0, cache_path, "WRITE_ROWS_ZERO", "month cache rows=0 after normalize")
            return None
        try:
            # 舊版相容 all cache：不得作為市場分流主來源，只作 legacy backup。
            _r5n7d_save_df_csv(x, cache_path, "legacy_all", m, "all", source_key=str(source_url or "legacy_all"))
            _r5n7d_save_df_csv(x, self.normalized_cache_path(m, None), "normalized_all", m, "all", source_key=str(source_url or "normalized_all"))

            # 市場分流 final/normalized cache。
            for mt in ("sii", "otc"):
                sub = x[x.get("market_type", "").astype(str).map(normalize_market_type).eq(mt)].copy() if "market_type" in x.columns else pd.DataFrame()
                if sub is None or sub.empty:
                    continue
                final_path = (REVENUE_CACHE_SII_DIR if mt == "sii" else REVENUE_CACHE_OTC_DIR) / f"revenue_{m}_{mt}.csv"
                normalized_path = self.normalized_cache_path(m, mt)
                _r5n7d_save_df_csv(sub, normalized_path, "normalized", m, mt, source_key=str(source_url or ""))
                _r5n7d_save_df_csv(sub, final_path, "final", m, mt, source_key=str(source_url or ""))
                log_info(f"[R5N7D][REVENUE_MARKET_CACHE][WRITE] month={m} market={mt} rows={len(sub)} final={final_path} normalized={normalized_path}")

            self._emit_cache_trace(m, "CACHE_WRITE", "PASS", len(x), cache_path)
            log_info(f"[R5N7D][REVENUE_MONTH_CACHE][WRITE] month={m} rows={len(x)} legacy={cache_path}")
            return cache_path
        except Exception as exc:
            self._emit_cache_trace(m, "CACHE_WRITE", "FAIL", 0, cache_path, "LOCAL_FILE_WRITE_FAIL", str(exc))
            log_warning(f"[R5N7D][REVENUE_MONTH_CACHE][WRITE_FAIL] month={m} file={cache_path}｜{exc}")
            return None

    def load_month_cache(self, month: str) -> pd.DataFrame:
        m = RevenueAccelerationEngine.normalize_month(month)
        if not m:
            return pd.DataFrame()
        cache_path = self.cache_path_for_month(m)
        if not cache_path.exists() or cache_path.stat().st_size <= 0:
            self._emit_cache_trace(m, "CACHE_VERIFY", "FAIL", 0, cache_path, "LOCAL_FILE_MISSING", "monthly revenue cache missing or empty")
            return pd.DataFrame()
        try:
            raw = safe_read_csv_auto(cache_path)
            x = self._normalize_month_cache_df(raw, m, source_url="OFFICIAL_MONTHLY_CACHE:" + str(cache_path))
            if x.empty:
                self._emit_cache_trace(m, "CACHE_VERIFY", "FAIL", 0, cache_path, "PARSE_ROWS_ZERO", "cache exists but valid rows=0 or month mismatch")
                return pd.DataFrame()
            month_match = bool(x["revenue_month"].astype(str).eq(m).all())
            if not month_match:
                self._emit_cache_trace(m, "CACHE_VERIFY", "FAIL", len(x), cache_path, "MONTH_MISMATCH", f"cache revenue_month not all {m}")
                return pd.DataFrame()
            self._emit_cache_trace(m, "CACHE_VERIFY", "PASS", len(x), cache_path)
            log_info(f"[R5L][REVENUE_MONTH_CACHE][VERIFY] month={m} rows={len(x)} file={cache_path}")
            return x
        except Exception as exc:
            self._emit_cache_trace(m, "CACHE_VERIFY", "FAIL", 0, cache_path, "PARSE_FAILED", str(exc))
            log_warning(f"[R5L][REVENUE_MONTH_CACHE][VERIFY_FAIL] month={m} file={cache_path}｜{exc}")
            return pd.DataFrame()

    def _read_remote_json_df(self, url: str, referer: str = "") -> tuple[pd.DataFrame, str]:
        resp = requests.get(
            url,
            timeout=45,
            headers={
                "User-Agent": "Mozilla/5.0",
                "Accept": "application/json,text/plain,*/*",
                "Referer": referer or ("https://www.tpex.org.tw/openapi/" if "tpex.org.tw" in str(url) else "https://openapi.twse.com.tw/"),
            },
        )
        status = str(resp.status_code)
        resp.raise_for_status()
        try:
            raw_dir = _r5n7d_revenue_pipeline_dir("raw", normalize_market_type(url), "openapi")
            raw_file = raw_dir / f"openapi_revenue_{datetime.now().strftime('%Y%m%d_%H%M%S_%f')}.json"
            raw_file.write_bytes(resp.content or b"")
            _r5n7d_append_manifest({
                "stage": "raw", "source_key": "openapi", "market_type": normalize_market_type(url) or "all",
                "path": str(raw_file), "bytes": int(raw_file.stat().st_size) if raw_file.exists() else 0,
                "status": "PASS", "request_url": str(url), "http_status": status
            })
        except Exception as raw_exc:
            log_warning(f"[R5N7D][REVENUE_RAW_OPENAPI_SAVE_FAIL] url={url}｜{raw_exc}")
        try:
            payload = resp.json()
        except Exception as exc:
            raise RuntimeError(f"OpenAPI cache JSON解析失敗：{exc}") from exc
        if isinstance(payload, dict):
            payload = payload.get("data") or payload.get("records") or payload.get("result") or []
        if not isinstance(payload, list):
            raise RuntimeError("OpenAPI cache JSON格式不是陣列")
        return pd.DataFrame(payload).astype(str).fillna(""), status

    def parse_revenue_openapi(self, raw: pd.DataFrame, source_label: str = "") -> tuple[pd.DataFrame, str]:
        if raw is None or raw.empty:
            return pd.DataFrame(), f"{source_label} cache raw rows=0"
        col_map = self._find_revenue_columns(raw)
        if "stock_id" not in col_map or "revenue" not in col_map or "revenue_month" not in col_map:
            return pd.DataFrame(), f"{source_label} cache欄位無法辨識：{list(raw.columns)[:20]}"
        rows = []
        for _, r in raw.iterrows():
            sid = normalize_stock_id(r.get(col_map.get("stock_id"), ""))
            month = RevenueAccelerationEngine.normalize_month(r.get(col_map.get("revenue_month"), ""))
            revenue = self._num(r.get(col_map.get("revenue"), np.nan), default=np.nan)
            if not sid or not month or (not np.isfinite(revenue)) or float(revenue) <= 0:
                continue
            rows.append({
                "stock_id": sid,
                "revenue_month": month,
                "revenue": float(revenue),
                "mom": self._num(r.get(col_map.get("mom"), np.nan), default=np.nan),
                "yoy": self._num(r.get(col_map.get("yoy"), np.nan), default=np.nan),
                "cumulative_revenue": self._num(r.get(col_map.get("cumulative_revenue"), np.nan), default=np.nan),
                "cumulative_yoy": self._num(r.get(col_map.get("cumulative_yoy"), np.nan), default=np.nan),
                "source_date": datetime.now().strftime("%Y-%m-%d"),
                "market_type": normalize_market_type(source_label),
                "update_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "cache_source_label": source_label,
            })
        out = pd.DataFrame(rows).drop_duplicates(subset=["stock_id", "revenue_month"], keep="last") if rows else pd.DataFrame()
        if out.empty:
            return out, f"{source_label} cache解析後有效 rows=0"
        return out, ""

    def save_cache_df(self, df: pd.DataFrame, source_tag: str = "official_openapi") -> Path | None:
        if df is None or df.empty:
            return None
        try:
            x = df.copy()
            if "revenue_month" in x.columns:
                x["revenue_month"] = x["revenue_month"].map(RevenueAccelerationEngine.normalize_month).fillna("").astype(str)
            if "revenue" in x.columns:
                x["revenue"] = pd.to_numeric(x["revenue"], errors="coerce")
            x = x[(x.get("revenue_month", pd.Series(dtype=str)).astype(str).ne("")) & (x.get("revenue", pd.Series(dtype=float)) > 0)].copy()
            if x.empty:
                return None
            out = self.cache_dir / f"revenue_openapi_{datetime.now().strftime('%Y%m%d_%H%M%S')}_{source_tag}.csv"
            x.to_csv(out, index=False, encoding="utf-8-sig")
            months = sorted(x['revenue_month'].astype(str).unique().tolist())
            # R5L.1：批次快取之外，同步拆出 revenue_YYYYMM.csv 逐月 cache。
            for m in months:
                self.write_month_cache(x[x['revenue_month'].astype(str).eq(str(m))].copy(), m, source_url="OFFICIAL_OPENAPI_BATCH_CACHE:" + str(out))
            log_info(f"[REVENUE][OPENAPI_CACHE] saved cache={out} rows={len(x)} months={months}")
            return out
        except Exception as exc:
            log_warning(f"[REVENUE][OPENAPI_CACHE] save cache failed：{exc}")
            return None

    def latest_cache_file(self) -> Path | None:
        files = sorted(self.cache_dir.glob("revenue_openapi_*.csv"), key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)
        return files[0] if files else None

    def read_latest_cache(self) -> pd.DataFrame:
        p = self.latest_cache_file()
        if p is None:
            return pd.DataFrame()
        last_error = None
        for enc in ("utf-8-sig", "utf-8", "big5", "cp950"):
            try:
                df = pd.read_csv(p, encoding=enc, dtype=str).fillna("")
                if df.empty:
                    return pd.DataFrame()
                df["stock_id"] = df.get("stock_id", "").map(normalize_stock_id)
                df["revenue_month"] = df.get("revenue_month", "").map(RevenueAccelerationEngine.normalize_month)
                for c in ["revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy"]:
                    if c not in df.columns:
                        df[c] = np.nan
                    df[c] = pd.to_numeric(df[c], errors="coerce")
                df = df[(df["stock_id"].astype(str).ne("")) & (df["revenue_month"].astype(str).ne("")) & (df["revenue"] > 0)].copy()
                if df.empty:
                    return pd.DataFrame()
                df["source_url"] = "OFFICIAL_OPENAPI_CACHE:" + str(p)
                if "source_date" not in df.columns:
                    df["source_date"] = datetime.now().strftime("%Y-%m-%d")
                if "update_time" not in df.columns:
                    df["update_time"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                return df[["stock_id", "revenue_month", "market_type", "revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy", "source_date", "source_url", "update_time"]].drop_duplicates(["stock_id", "revenue_month"], keep="last")
            except Exception as exc:
                last_error = exc
                continue
        log_warning(f"[REVENUE][OPENAPI_CACHE] read latest cache failed：{last_error}")
        return pd.DataFrame()

    def read_all_caches(self, max_files: int = 80) -> pd.DataFrame:
        """R4F：讀取所有本地 revenue_openapi_*.csv 快取，用於補歷史缺月。

        原 R4A 只讀 latest cache，若最新官方 OpenAPI 只有 202604，就永遠補不到
        202602/202603。此處只讀本機既有快取，不覆蓋 DB，仍維持 append-only。
        """
        files = sorted(
            list(self.cache_dir.glob("revenue_*.csv")) + list(self.cache_dir.glob("revenue_openapi_*.csv")),
            key=lambda p: p.stat().st_mtime if p.exists() else 0,
            reverse=True,
        )[:int(max_files or 80)]
        parts = []
        for p in files:
            for enc in ("utf-8-sig", "utf-8", "big5", "cp950"):
                try:
                    df = pd.read_csv(p, encoding=enc, dtype=str).fillna("")
                    if df is None or df.empty:
                        break
                    df["stock_id"] = df.get("stock_id", "").map(normalize_stock_id)
                    df["revenue_month"] = df.get("revenue_month", "").map(RevenueAccelerationEngine.normalize_month)
                    for c in ["revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy"]:
                        if c not in df.columns:
                            df[c] = np.nan
                        df[c] = pd.to_numeric(df[c], errors="coerce")
                    df = df[(df["stock_id"].astype(str).ne("")) & (df["revenue_month"].astype(str).ne("")) & (df["revenue"] > 0)].copy()
                    if df.empty:
                        break
                    if "source_date" not in df.columns:
                        df["source_date"] = datetime.now().strftime("%Y-%m-%d")
                    if "update_time" not in df.columns:
                        df["update_time"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                    df["source_url"] = "OFFICIAL_OPENAPI_CACHE:" + str(p)
                    parts.append(df[["stock_id", "revenue_month", "market_type", "revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy", "source_date", "source_url", "update_time"]])
                    break
                except Exception:
                    continue
        if not parts:
            return pd.DataFrame()
        out = pd.concat(parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")
        log_info(f"[REVENUE][OPENAPI_CACHE][ALL_LOCAL] files={len(files)} rows={len(out)} months={sorted(out['revenue_month'].astype(str).unique().tolist())[-12:]}")
        return out

    def download_latest_cache(self, include_optional: bool = False) -> tuple[pd.DataFrame, Path | None, str]:
        parts, errors = [], []
        endpoints = dict(self.endpoints)
        if include_optional:
            endpoints.update(self.optional_endpoints)
        for label, url in endpoints.items():
            try:
                raw, status = self._read_remote_json_df(url)
                parsed, err = self.parse_revenue_openapi(raw, source_label=label)
                if parsed is None or parsed.empty:
                    errors.append(err or f"{label} rows=0")
                    continue
                parsed["source_url"] = url
                parts.append(parsed)
                log_info(f"[REVENUE][OPENAPI_CACHE][{label}] download rows={len(parsed)} status={status}")
            except Exception as exc:
                errors.append(f"{label}:{exc}")
                log_warning(f"[REVENUE][OPENAPI_CACHE][{label}] download failed：{exc}")
        df = pd.concat(parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last") if parts else pd.DataFrame()
        cache_path = self.save_cache_df(df, source_tag="download") if df is not None and not df.empty else None
        if df is not None and not df.empty:
            df["source_url"] = "OFFICIAL_OPENAPI_CACHE:" + str(cache_path or "download_memory")
        return df, cache_path, " ; ".join(errors)

    def _flatten_revenue_html_table(self, df: pd.DataFrame) -> pd.DataFrame:
        """R4F：MOPS HTML 月營收表格欄位扁平化，支援多層表頭。"""
        if df is None or df.empty:
            return pd.DataFrame()
        x = df.copy()
        flat_cols = []
        for c in x.columns:
            if isinstance(c, tuple):
                parts = [str(v).strip() for v in c if str(v).strip() and not str(v).startswith("Unnamed")]
                flat_cols.append("-".join(parts) if parts else "")
            else:
                flat_cols.append(str(c).strip())
        x.columns = flat_cols
        x = x.loc[:, [c for c in x.columns if str(c).strip()]]
        return x.fillna("")

    def _candidate_local_c04003_zip_paths(self, target_month: str) -> list[Path]:
        """R5M：尋找已手動下載或已快取的 TWSE index04 C04003 ZIP。"""
        m = RevenueAccelerationEngine.normalize_month(target_month)
        if not m:
            return []
        names = [f"{m}_C04003.zip", f"{m}_c04003.zip"]
        folders = [TWSE_INDEX04_C04003_CACHE_DIR, self.cache_dir, RUNTIME_DIR, BASE_DIR, Path.cwd()]
        try:
            folders.append(Path("/mnt/data"))  # 測試環境用；正式 EXE 不依賴。
        except Exception:
            pass
        out, seen = [], set()
        for folder in folders:
            try:
                for name in names:
                    p = Path(folder) / name
                    if str(p) not in seen:
                        seen.add(str(p)); out.append(p)
            except Exception:
                continue
        return out

    def _twse_index04_report_info(self, report_code: str) -> dict:
        """R5N3：取得上市公司月報定義。"""
        code = str(report_code or "").strip().upper()
        return dict(TWSE_INDEX04_REPORT_DEFINITIONS.get(code, {}))

    def _build_twse_index04_rwd_count_url(self, target_month: str, report_code: str) -> str:
        """R5N3：依 TWSE index04 左下角真實下載規則建立 count 下載 URL。

        規則來自實際瀏覽器左下角下載網址：
        /rwd/zh/statistics/count?l1=上市公司月報&l2=【xxx】月報&url=/staticFiles/inspection/inspection/04/NNN/YYYYMM_C0400N.zip
        """
        m = RevenueAccelerationEngine.normalize_month(target_month)
        info = self._twse_index04_report_info(report_code)
        if not m or not info:
            return ""
        code = str(report_code).strip().upper()
        seq = str(info.get("seq") or "").strip()
        name = str(info.get("name") or "").strip()
        if not seq or not name:
            return ""
        static_path = f"/staticFiles/inspection/inspection/04/{seq}/{m}_{code}.zip"
        params = {
            "l1": TWSE_INDEX04_L1,
            "l2": f"【{name}】月報",
            "url": static_path,
        }
        req = requests.Request("GET", TWSE_INDEX04_RWD_COUNT_URL, params=params).prepare()
        return str(req.url or "")

    def _save_non_zip_debug_file(self, target_month: str, report_code: str, response, label: str = "") -> Path | None:
        """R5N3：非 ZIP 回應必須落檔，避免現場只看到 FAIL 沒有證據。"""
        try:
            m = RevenueAccelerationEngine.normalize_month(target_month) or str(target_month or "unknown")
            code = str(report_code or "unknown").upper()
            debug_dir = TWSE_INDEX04_ALL_REPORTS_CACHE_DIR / m / "_fail_debug"
            debug_dir.mkdir(parents=True, exist_ok=True)
            suffix = "html"
            ctype = ""
            try:
                ctype = str(response.headers.get("Content-Type", "") or "")
            except Exception:
                pass
            if "json" in ctype.lower():
                suffix = "json"
            elif "text" in ctype.lower() or "html" in ctype.lower():
                suffix = "html"
            else:
                suffix = "bin"
            stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            safe_label = re.sub(r"[^A-Za-z0-9_\-]", "_", str(label or "not_zip"))[:40]
            out = debug_dir / f"{m}_{code}_{safe_label}_{stamp}.{suffix}"
            content = getattr(response, "content", b"") or b""
            out.write_bytes(content)
            meta = debug_dir / f"{m}_{code}_{safe_label}_{stamp}.txt"
            try:
                meta.write_text(
                    "url=" + str(getattr(response, "url", "")) + "\n" +
                    "status=" + str(getattr(response, "status_code", "")) + "\n" +
                    "content_type=" + ctype + "\n" +
                    "bytes=" + str(len(content)) + "\n" +
                    "head=" + repr(content[:64]) + "\n",
                    encoding="utf-8",
                )
            except Exception:
                pass
            log_warning(f"[R5N3][TWSE_INDEX04][NON_ZIP_SAVED] month={m} report={code} file={out}")
            return out
        except Exception:
            return None

    def _download_twse_index04_report_zip(self, target_month: str, report_code: str) -> tuple[Path | None, str, str]:
        """R5N3：下載指定月份/指定月報代號 ZIP 到本機。

        主方法：TWSE rwd/zh/statistics/count + url=/staticFiles/inspection/inspection/04/NNN/YYYYMM_C0400N.zip。
        成功條件：HTTP 200 且 response.content 以 PK 開頭。
        """
        m = RevenueAccelerationEngine.normalize_month(target_month)
        code = str(report_code or "").strip().upper()
        info = self._twse_index04_report_info(code)
        if not m:
            return None, "", "invalid month"
        if not info:
            return None, "", f"unknown report_code={report_code}"

        month_dir = TWSE_INDEX04_ALL_REPORTS_CACHE_DIR / m
        month_dir.mkdir(parents=True, exist_ok=True)
        out = month_dir / f"{m}_{code}.zip"
        if out.exists() and out.stat().st_size > 0:
            try:
                if out.read_bytes()[:4].startswith(b"PK"):
                    return out, "LOCAL_MONTHLY_REPORT:" + str(out), ""
                else:
                    log_warning(f"[R5N3][TWSE_INDEX04][LOCAL_INVALID] month={m} report={code} file={out}")
            except Exception:
                pass

        url = self._build_twse_index04_rwd_count_url(m, code)
        if not url:
            return None, "", f"build count url failed report={code}"
        headers = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120 Safari/537.36",
            "Accept": "application/zip,application/octet-stream,*/*",
            "Referer": TWSE_INDEX04_PAGE_URL,
        }
        try:
            resp = requests.get(url, headers=headers, timeout=60, allow_redirects=True)
            request_url = str(getattr(resp, "url", url) or url)
            if resp.status_code != 200:
                self._save_non_zip_debug_file(m, code, resp, label=f"HTTP{resp.status_code}")
                return None, request_url, f"HTTP{resp.status_code}"
            content = resp.content or b""
            if not self._is_valid_zip_bytes(content):
                self._save_non_zip_debug_file(m, code, resp, label="not_zip")
                return None, request_url, f"not_zip_or_too_small bytes={len(content)} content_type={resp.headers.get('Content-Type','')}"
            out.write_bytes(content)
            log_info(f"[R5N3][TWSE_INDEX04][ZIP_OK] month={m} report={code} file={out} bytes={len(content)} url={request_url}")
            return out, request_url, ""
        except Exception as exc:
            return None, url, str(exc)

    def _extract_twse_index04_report_zip(self, zip_path: Path, target_month: str, report_code: str) -> list[Path]:
        """R5N3：解壓指定月報 ZIP，回傳解壓出的檔案清單。"""
        files: list[Path] = []
        try:
            m = RevenueAccelerationEngine.normalize_month(target_month)
            code = str(report_code or "").strip().upper()
            extract_dir = TWSE_INDEX04_ALL_REPORTS_CACHE_DIR / m / code
            extract_dir.mkdir(parents=True, exist_ok=True)
            with zipfile.ZipFile(zip_path) as zf:
                for member in zf.namelist():
                    zf.extract(member, extract_dir)
                    files.append(extract_dir / member)
            log_info(f"[R5N3][TWSE_INDEX04][ZIP_EXTRACT_OK] month={m} report={code} files={len(files)} dir={extract_dir}")
        except Exception as exc:
            log_warning(f"[R5N3][TWSE_INDEX04][ZIP_EXTRACT_FAIL] month={target_month} report={report_code} file={zip_path}｜{exc}")
        return files

    def download_twse_index04_all_reports_for_month(self, target_month: str, force_download: bool = False) -> pd.DataFrame:
        """R5N3：當 UI 選到月份時，下載該月份上市公司月報全部內容 ZIP（C04001~C04004）。

        回傳下載明細 DataFrame；C04003 仍會由既有 Revenue Cache 流程解析。
        """
        m = RevenueAccelerationEngine.normalize_month(target_month)
        rows = []
        if not m:
            return pd.DataFrame()
        for code, info in TWSE_INDEX04_REPORT_DEFINITIONS.items():
            month_zip = TWSE_INDEX04_ALL_REPORTS_CACHE_DIR / m / f"{m}_{code}.zip"
            if force_download and month_zip.exists():
                try:
                    month_zip.unlink()
                except Exception:
                    pass
            zip_path, url, err = self._download_twse_index04_report_zip(m, code)
            extracted = []
            if zip_path is not None and Path(zip_path).exists():
                extracted = self._extract_twse_index04_report_zip(Path(zip_path), m, code)
            zip_ok = bool(zip_path is not None and Path(zip_path).exists())
            zip_bytes = int(Path(zip_path).stat().st_size) if zip_ok else 0
            rows.append({
                "月份": m,
                "報表代號": code,
                "報表名稱": str(info.get("name") or ""),
                "下載狀態": "PASS" if zip_ok else "FAIL",
                "ZIP_PK驗證": "PASS" if zip_ok and self._is_valid_zip_bytes(Path(zip_path).read_bytes()) else ("FAIL" if not zip_ok else "WARN"),
                "ZIP大小bytes": zip_bytes,
                "ZIP路徑": str(zip_path or ""),
                "解壓檔數": len(extracted),
                "解壓路徑": str((TWSE_INDEX04_ALL_REPORTS_CACHE_DIR / m / code) if extracted else ""),
                "下載網址": url,
                "錯誤訊息": err,
                "下載時間": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            })
        manifest = pd.DataFrame(rows)
        try:
            out = TWSE_INDEX04_ALL_REPORTS_CACHE_DIR / m / f"index04_all_reports_{m}.csv"
            out.parent.mkdir(parents=True, exist_ok=True)
            manifest.to_csv(out, index=False, encoding="utf-8-sig")
            _r5n8d_write_official_source_gate_csv(m, manifest, "index04_all_reports_download")
            log_info(f"[R5N3][TWSE_INDEX04][ALL_REPORTS_MANIFEST] month={m} file={out}")
        except Exception as exc:
            log_warning(f"[R5N3][TWSE_INDEX04][ALL_REPORTS_MANIFEST_FAIL] month={m}｜{exc}")
        return manifest

    def _discover_twse_index04_c04003_url(self, target_month: str) -> str:
        """R5N3：保留舊方法名稱，但改為產生已驗證的 rwd/zh/statistics/count C04003 URL。"""
        return self._build_twse_index04_rwd_count_url(target_month, TWSE_INDEX04_REVENUE_REPORT_CODE)

    def _is_valid_zip_bytes(self, content: bytes) -> bool:
        """R5N3：確認下載內容是否真為 ZIP。TWSE 無資料時可能 HTTP 200 但回 HTML，不能直接解壓。"""
        try:
            return bool(content) and len(content) >= 1024 and bytes(content[:4]).startswith(b"PK")
        except Exception:
            return False

    def _download_twse_index04_backend_zip(self, target_month: str) -> tuple[Path | None, str, str]:
        """R5N3：backward-compatible wrapper。

        舊版 R5N2 使用 https://twse.com.tw?download=zip&type=C... 已確認會回首頁/解析失敗。
        現改為下載 C04003 的 rwd count ZIP。此函式保留名稱，避免其他呼叫點失效。"""
        return self._download_twse_index04_report_zip(target_month, TWSE_INDEX04_REVENUE_REPORT_CODE)

    def _download_twse_index04_c04003_zip(self, target_month: str) -> tuple[Path | None, str, str]:
        """R5N3：下載/取得 TWSE index04 C04003 ZIP。回傳(zip_path, url, error)。

        優先順序：
        1. 本機已存在 ZIP（人工下載或前次快取）。
        2. TWSE rwd/zh/statistics/count 真實下載入口；並同步下載同月份 C04001~C04004 全部內容檔。
        3. 舊 staticFiles hard-code URL（只作最後備援）。
        """
        m = RevenueAccelerationEngine.normalize_month(target_month)
        if not m:
            return None, "", "invalid month"
        for p in self._candidate_local_c04003_zip_paths(m):
            try:
                if p.exists() and p.stat().st_size > 0:
                    raw = p.read_bytes()[:4]
                    if not raw.startswith(b"PK"):
                        log_warning(f"[R5N3][TWSE_INDEX04][LOCAL_ZIP_INVALID] month={m} file={p} head={raw!r}")
                        continue
                    target = TWSE_INDEX04_C04003_CACHE_DIR / f"{m}_C04003.zip"
                    if p.resolve() != target.resolve():
                        target.parent.mkdir(parents=True, exist_ok=True)
                        try:
                            shutil.copy2(p, target)
                            p = target
                        except Exception:
                            pass
                    return p, "LOCAL_FILE:" + str(p), ""
            except Exception:
                continue

        all_manifest = pd.DataFrame()
        if TWSE_INDEX04_RWD_DOWNLOAD_ALL_REPORTS:
            try:
                all_manifest = self.download_twse_index04_all_reports_for_month(m, force_download=False)
            except Exception as exc:
                log_warning(f"[R5N3][TWSE_INDEX04][ALL_REPORTS_DOWNLOAD_FAIL] month={m}｜{exc}")
        r = None
        if all_manifest is not None and not all_manifest.empty:
            try:
                r = all_manifest[(all_manifest["報表代號"].astype(str) == TWSE_INDEX04_REVENUE_REPORT_CODE) & (all_manifest["下載狀態"].astype(str) == "PASS")].tail(1)
            except Exception:
                r = None
        if r is not None and not r.empty:
            zip_file = Path(str(r.iloc[-1].get("ZIP路徑") or ""))
            if zip_file.exists():
                target = TWSE_INDEX04_C04003_CACHE_DIR / f"{m}_C04003.zip"
                target.parent.mkdir(parents=True, exist_ok=True)
                try:
                    shutil.copy2(zip_file, target)
                    zip_file = target
                except Exception:
                    pass
                return zip_file, "OFFICIAL_TWSE_INDEX04_RWD_COUNT_DOWNLOAD:" + str(r.iloc[-1].get("下載網址") or ""), ""

        # 直接再抓一次 C04003，避免 all reports 有單一檔案失敗時沒有二次機會。
        backend_zip, backend_url, backend_error = self._download_twse_index04_report_zip(m, TWSE_INDEX04_REVENUE_REPORT_CODE)
        if backend_zip is not None and Path(backend_zip).exists():
            target = TWSE_INDEX04_C04003_CACHE_DIR / f"{m}_C04003.zip"
            target.parent.mkdir(parents=True, exist_ok=True)
            try:
                shutil.copy2(backend_zip, target)
                backend_zip = target
            except Exception:
                pass
            return backend_zip, "OFFICIAL_TWSE_INDEX04_RWD_COUNT_DOWNLOAD:" + backend_url, ""

        urls = []
        discovered = self._discover_twse_index04_c04003_url(m)
        if discovered:
            urls.append(discovered)
        for tpl in TWSE_INDEX04_C04003_URL_TEMPLATES:
            try:
                u = tpl.format(month=m, year=m[:4])
                if u not in urls:
                    urls.append(u)
            except Exception:
                continue
        errors = ["RWD_COUNT:" + backend_error] if backend_error else []
        out = TWSE_INDEX04_C04003_CACHE_DIR / f"{m}_C04003.zip"
        for url in urls:
            try:
                resp = requests.get(
                    url,
                    timeout=60,
                    headers={"User-Agent": "Mozilla/5.0", "Accept": "application/zip,application/octet-stream,*/*", "Referer": TWSE_INDEX04_PAGE_URL},
                )
                if resp.status_code != 200:
                    self._save_non_zip_debug_file(m, TWSE_INDEX04_REVENUE_REPORT_CODE, resp, label=f"HTTP{resp.status_code}")
                    errors.append(f"{url}:HTTP{resp.status_code}"); continue
                content = resp.content or b""
                if not self._is_valid_zip_bytes(content):
                    self._save_non_zip_debug_file(m, TWSE_INDEX04_REVENUE_REPORT_CODE, resp, label="not_zip_fallback")
                    errors.append(f"{url}:not_zip_or_too_small bytes={len(content)}"); continue
                out.parent.mkdir(parents=True, exist_ok=True)
                out.write_bytes(content)
                log_info(f"[R5N3][TWSE_INDEX04][ZIP_DOWNLOAD_FALLBACK_OK] month={m} file={out} bytes={len(content)} url={url}")
                return out, url, ""
            except Exception as exc:
                errors.append(f"{url}:{exc}")
        return None, " | ".join(urls), " ; ".join(errors)

    def _parse_twse_c04003_excel(self, excel_path: Path, target_month: str, source_url: str = "") -> pd.DataFrame:
        """R5M：解析 TWSE C04003 國內上市公司營業收入彙總表。

        A欄 = 股票代號+股票名稱；B欄 = 上月營收；C欄 = 本月營收；
        D欄 = 本年度累計；E欄 = 去年同月；F欄 = 去年累計；H欄 = 累計增減%。
        月增率與單月 YoY 由 B/C/E 欄計算。
        """
        m = RevenueAccelerationEngine.normalize_month(target_month)
        if not m:
            return pd.DataFrame()
        excel_path = Path(excel_path)
        try:
            raw = safe_read_excel(excel_path)
        except Exception:
            converted = convert_xls_to_xlsx_force(excel_path, TWSE_INDEX04_C04003_CACHE_DIR / f"{m}_C04003.xlsx")
            if converted is None:
                raise
            raw = pd.read_excel(converted, sheet_name=0, header=None, engine="openpyxl")
        try:
            converted_path = TWSE_INDEX04_C04003_CACHE_DIR / f"{m}_C04003.xlsx"
            if converted_path.exists():
                raw = pd.read_excel(converted_path, sheet_name=0, header=None, engine="openpyxl")
        except Exception:
            pass
        if raw is None or raw.empty:
            return pd.DataFrame()
        x = raw.copy().fillna("")
        rows = []
        for _, r in x.iterrows():
            first = str(r.iloc[0] if len(r) > 0 else "").strip()
            mt = re.match(r"^\s*(\d{4,5})\s+(.+?)\s*$", first)
            if not mt:
                continue
            sid = normalize_stock_id(mt.group(1))
            if not sid or not re.fullmatch(r"\d{4,5}", sid):
                continue
            prev_month_rev = self._num(r.iloc[1] if len(r) > 1 else np.nan, default=np.nan)
            cur_month_rev = self._num(r.iloc[2] if len(r) > 2 else np.nan, default=np.nan)
            cumulative_rev = self._num(r.iloc[3] if len(r) > 3 else np.nan, default=np.nan)
            last_year_month_rev = self._num(r.iloc[4] if len(r) > 4 else np.nan, default=np.nan)
            last_year_cum_rev = self._num(r.iloc[5] if len(r) > 5 else np.nan, default=np.nan)
            cumulative_yoy = self._num(r.iloc[7] if len(r) > 7 else np.nan, default=np.nan)
            if not np.isfinite(cur_month_rev) or cur_month_rev <= 0:
                continue
            mom = np.nan
            if np.isfinite(prev_month_rev) and prev_month_rev != 0:
                mom = round((cur_month_rev - prev_month_rev) / abs(prev_month_rev) * 100.0, 4)
            yoy = np.nan
            if np.isfinite(last_year_month_rev) and last_year_month_rev != 0:
                yoy = round((cur_month_rev - last_year_month_rev) / abs(last_year_month_rev) * 100.0, 4)
            if (not np.isfinite(cumulative_yoy)) and np.isfinite(cumulative_rev) and np.isfinite(last_year_cum_rev) and last_year_cum_rev != 0:
                cumulative_yoy = round((cumulative_rev - last_year_cum_rev) / abs(last_year_cum_rev) * 100.0, 4)
            rows.append({
                "stock_id": sid,
                "revenue_month": m,
                "market_type": "sii",
                "revenue": float(cur_month_rev),
                "mom": mom,
                "yoy": yoy,
                "cumulative_revenue": cumulative_rev if np.isfinite(cumulative_rev) else np.nan,
                "cumulative_yoy": cumulative_yoy if np.isfinite(cumulative_yoy) else np.nan,
                "source_date": f"{m[:4]}-{m[4:6]}",
                "source_url": source_url or f"TWSE_INDEX04_C04003:{m}",
                "update_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            })
        out = pd.DataFrame(rows)
        if out.empty:
            try:
                debug_dir = TWSE_INDEX04_GATE_REPORT_DIR / m
                debug_dir.mkdir(parents=True, exist_ok=True)
                (debug_dir / f"{m}_C04003_parse_zero_rows.txt").write_text(
                    f"excel_path={excel_path}\nsource_url={source_url}\nraw_shape={getattr(raw, 'shape', '')}\n",
                    encoding="utf-8"
                )
            except Exception:
                pass
            return out
        out = out.drop_duplicates(["stock_id", "revenue_month"], keep="last")
        valid_rows = int(len(out))
        if valid_rows < TWSE_INDEX04_C04003_MIN_VALID_ROWS:
            try:
                debug_dir = TWSE_INDEX04_GATE_REPORT_DIR / m
                debug_dir.mkdir(parents=True, exist_ok=True)
                reject_path = debug_dir / f"{m}_C04003_parse_rejected_rows.csv"
                out.to_csv(reject_path, index=False, encoding="utf-8-sig")
                (debug_dir / f"{m}_C04003_parse_rejected_reason.txt").write_text(
                    f"valid_rows={valid_rows}\nmin_required={TWSE_INDEX04_C04003_MIN_VALID_ROWS}\nexcel_path={excel_path}\nsource_url={source_url}\n",
                    encoding="utf-8"
                )
            except Exception:
                pass
            log_warning(f"[R5N8D][TWSE_INDEX04][C04003_PARSE_REJECT] month={m} rows={valid_rows} min={TWSE_INDEX04_C04003_MIN_VALID_ROWS} file={excel_path}")
            return pd.DataFrame()
        gate_df = pd.DataFrame([{
            "月份": m,
            "報表代號": "C04003",
            "階段": "PARSE",
            "狀態": "PASS",
            "有效筆數": valid_rows,
            "最低門檻": TWSE_INDEX04_C04003_MIN_VALID_ROWS,
            "來源檔案": str(excel_path),
            "來源網址": source_url,
            "輸出時間": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        }])
        _r5n8d_write_official_source_gate_csv(m, gate_df, "c04003_parse")
        return out[["stock_id", "revenue_month", "market_type", "revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy", "source_date", "source_url", "update_time"]]

    def download_twse_index04_c04003_month_cache(self, target_month: str) -> pd.DataFrame:
        """R5M：用 TWSE index04 C04003 歷史 ZIP 補指定月份上市公司月營收。"""
        m = RevenueAccelerationEngine.normalize_month(target_month)
        if not m:
            return pd.DataFrame()
        zip_path, source_url, zip_error = self._download_twse_index04_c04003_zip(m)
        if zip_path is None or not Path(zip_path).exists():
            self._emit_cache_trace(m, "INDEX04_ZIP_DOWNLOAD", "FAIL", 0, None, "HTTP_FAIL", zip_error)
            log_warning(f"[R5M][TWSE_INDEX04][ZIP_FAIL] month={m}｜{zip_error}")
            return pd.DataFrame()
        try:
            try:
                raw_zip_dir = _r5n7d_revenue_pipeline_dir("raw", "sii", "index04_c04003")
                raw_zip = raw_zip_dir / f"{m}_C04003.zip"
                shutil.copy2(zip_path, raw_zip)
                _r5n7d_append_manifest({"stage": "raw", "source_key": "index04_c04003", "revenue_month": m, "market_type": "sii", "path": str(raw_zip), "bytes": int(raw_zip.stat().st_size), "status": "PASS", "request_url": str(source_url or "")})
            except Exception as raw_exc:
                log_warning(f"[R5N7D][REVENUE_RAW_INDEX04_SAVE_FAIL] month={m}｜{raw_exc}")
            with zipfile.ZipFile(zip_path) as zf:
                names = [n for n in zf.namelist() if n.lower().endswith((".xls", ".xlsx"))]
                if not names:
                    self._emit_cache_trace(m, "INDEX04_ZIP_PARSE", "FAIL", 0, zip_path, "PARSE_ROWS_ZERO", "zip has no xls/xlsx")
                    return pd.DataFrame()
                member = names[0]
                extract_dir = TWSE_INDEX04_C04003_CACHE_DIR / m
                extract_dir.mkdir(parents=True, exist_ok=True)
                zf.extract(member, extract_dir)
                xls_path = extract_dir / member
            should_delete_zip = (
                TWSE_INDEX04_BACKEND_DELETE_ZIP_AFTER_EXTRACT
                and str(source_url or "").startswith("OFFICIAL_TWSE_INDEX04_BACKEND_DOWNLOAD:")
                and Path(zip_path).exists()
            )
            converted_path = TWSE_INDEX04_C04003_CACHE_DIR / f"{m}_C04003.xlsx"
            if xls_path.suffix.lower() == ".xls":
                converted = convert_xls_to_xlsx_force(xls_path, converted_path, log_cb=lambda msg: log_info(f"[R5M][TWSE_INDEX04] {msg}"))
                excel_path = converted if converted is not None else xls_path
            else:
                excel_path = xls_path
            df = self._parse_twse_c04003_excel(excel_path, m, source_url=f"OFFICIAL_TWSE_INDEX04_C04003:{source_url}")
            if df is None or df.empty:
                self._emit_cache_trace(m, "INDEX04_PARSE", "FAIL", 0, zip_path, "PARSE_ROWS_ZERO", "C04003 parsed rows=0")
                return pd.DataFrame()
            month_cache_path = self.write_month_cache(df, m, source_url=f"OFFICIAL_TWSE_INDEX04_C04003_CACHE:{zip_path}")
            df["source_url"] = "OFFICIAL_TWSE_INDEX04_C04003_CACHE:" + str(month_cache_path or zip_path)
            self._emit_cache_trace(m, "INDEX04_PARSE", "PASS", len(df), zip_path)
            log_info(f"[R5N2][TWSE_INDEX04][C04003_OK] month={m} rows={len(df)} zip={zip_path} source={source_url}")
            if should_delete_zip:
                try:
                    Path(zip_path).unlink()
                    log_info(f"[R5N2][TWSE_INDEX04_BACKEND][ZIP_DELETED_AFTER_EXTRACT] month={m} file={zip_path}")
                except Exception as _del_exc:
                    log_warning(f"[R5N2][TWSE_INDEX04_BACKEND][ZIP_DELETE_FAIL] month={m} file={zip_path}｜{_del_exc}")
            return df[["stock_id", "revenue_month", "market_type", "revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy", "source_date", "source_url", "update_time"]]
        except Exception as exc:
            self._emit_cache_trace(m, "INDEX04_PARSE", "FAIL", 0, zip_path, "PARSE_FAILED", str(exc))
            log_warning(f"[R5M][TWSE_INDEX04][C04003_FAIL] month={m} zip={zip_path}｜{exc}")
            return pd.DataFrame()

    def ensure_c04003_revenue_cache(self, months: list[str], force_download: bool = False, write_db: bool = False, db: DBManager | None = None) -> tuple[pd.DataFrame, pd.DataFrame]:
        """R5N：依 UI 選取月份逐月建立 TWSE index04/C04003 本機 Revenue Cache。

        - 不再寫死 202602/202603/202604。
        - 先讀 data/revenue_cache/revenue_YYYYMM.csv。
        - 缺檔或 force_download=True 時，自動下載 index04 C04003 ZIP、解析 XLS/XLSX、轉 CSV Cache。
        - write_db=True 時，以 append-only 寫入 external_revenue_history。
        - 回傳：summary_df, combined_df。
        """
        norm_months = []
        for m in (months or []):
            mm = RevenueAccelerationEngine.normalize_month(m)
            if mm and mm not in norm_months:
                norm_months.append(mm)
        summary_rows = []
        data_parts = []
        for mm in norm_months:
            cache_path = self.monthly_cache_path(mm, "sii")
            legacy_cache_path = self.cache_path_for_month(mm)
            source = "CACHE_SII_FINAL"
            df = pd.DataFrame()
            if not force_download:
                df = self.read_month_cache(mm, "sii")
                if df is None or df.empty:
                    source = "CACHE_LEGACY_ALL"
                    if legacy_cache_path.exists() and legacy_cache_path.stat().st_size > 0:
                        df = self.load_month_cache(mm)
            if df is None or df.empty:
                source = "TWSE_INDEX04_C04003"
                df = self.download_twse_index04_c04003_month_cache(mm)
            rows = int(len(df)) if isinstance(df, pd.DataFrame) else 0
            status = "PASS" if rows > 0 else ("NOT_DUE" if _r5n7d_is_revenue_not_due(mm) else "FAIL")
            if rows > 0:
                data_parts.append(df.copy())
            summary_rows.append({
                "月份": mm,
                "狀態": status,
                "資料筆數": rows,
                "來源": source,
                "Cache檔案": str(cache_path),
                "Legacy相容Cache": str(legacy_cache_path),
                "NormalizedCache": str(self.normalized_cache_path(mm, "sii")),
                "說明": "已建立逐月Cache" if rows > 0 else ("月報未到期，非缺資料" if status == "NOT_DUE" else "未取得有效 C04003 月營收資料"),
                "更新時間": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            })
        combined = pd.concat(data_parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last") if data_parts else pd.DataFrame()
        if write_db and db is not None and combined is not None and not combined.empty:
            inserted = self.upsert_external_revenue_history(db, combined, append_only=False)
            for row in summary_rows:
                row["DB寫入模式"] = "INSERT_OR_IGNORE"
                row["DB寫入總筆數"] = inserted
        summary = pd.DataFrame(summary_rows)
        try:
            manifest = {
                "version": "R5N2_TWSE_INDEX04_BACKEND_ZIP_DOWNLOAD_FIX_20260609",
                "months": norm_months,
                "force_download": bool(force_download),
                "write_db": bool(write_db),
                "summary": summary_rows,
                "updated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            }
            (self.monthly_cache_dir / "revenue_cache_manifest.json").write_text(json.dumps(manifest, ensure_ascii=False, indent=2), encoding="utf-8")
        except Exception as exc:
            log_warning(f"[R5N][REVENUE_CACHE_MANIFEST][WRITE_FAIL] {exc}")
        return summary, combined

    def upsert_external_revenue_history(self, db: DBManager, df: pd.DataFrame, append_only: bool = True) -> int:
        """R5N：將逐月 Cache 寫入 external_revenue_history。

        append_only=True 時使用 INSERT OR IGNORE，不覆蓋既有有效資料。
        """
        if db is None or df is None or df.empty:
            return 0
        # 多月份 DataFrame 必須逐月正規化；不可用第一個月份過濾整批資料，否則只會寫入第一個月。
        parts = []
        if "revenue_month" not in df.columns:
            return 0
        norm_month_series = df["revenue_month"].astype(str).map(RevenueAccelerationEngine.normalize_month)
        for mm in sorted(set(norm_month_series.tolist())):
            if not mm:
                continue
            part_raw = df[norm_month_series.eq(mm)].copy()
            part = self._normalize_month_cache_df(part_raw, mm, source_url="R5N_CACHE_DB_WRITE")
            if part is not None and not part.empty:
                parts.append(part)
        x = pd.concat(parts, ignore_index=True) if parts else pd.DataFrame()
        if x.empty:
            return 0
        rows = []
        for _, r in x.iterrows():
            rows.append((
                str(r.get("stock_id", "")),
                str(r.get("revenue_month", "")),
                normalize_market_type(r.get("market_type", "") or r.get("source_url", "")),
                float(r.get("revenue")) if pd.notna(r.get("revenue")) else None,
                float(r.get("mom")) if pd.notna(r.get("mom")) else None,
                float(r.get("yoy")) if pd.notna(r.get("yoy")) else None,
                float(r.get("cumulative_revenue")) if pd.notna(r.get("cumulative_revenue")) else None,
                float(r.get("cumulative_yoy")) if pd.notna(r.get("cumulative_yoy")) else None,
                str(r.get("source_url", "")),
                str(r.get("source_date", "")),
                str(r.get("update_time", datetime.now().strftime("%Y-%m-%d %H:%M:%S"))),
            ))
        sql_insert_ignore = """
            INSERT OR IGNORE INTO external_revenue_history(
                stock_id, revenue_month, market_type, revenue, mom, yoy, cumulative_revenue, cumulative_yoy,
                source_url, source_date, update_time
            ) VALUES(?,?,?,?,?,?,?,?,?,?,?)
        """
        sql_upsert_repair = """
            INSERT INTO external_revenue_history(
                stock_id, revenue_month, market_type, revenue, mom, yoy, cumulative_revenue, cumulative_yoy,
                source_url, source_date, update_time
            ) VALUES(?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(stock_id, revenue_month) DO UPDATE SET
                revenue=CASE WHEN COALESCE(external_revenue_history.revenue,0)<=0 THEN excluded.revenue ELSE external_revenue_history.revenue END,
                mom=CASE WHEN external_revenue_history.mom IS NULL THEN excluded.mom ELSE external_revenue_history.mom END,
                yoy=CASE WHEN external_revenue_history.yoy IS NULL THEN excluded.yoy ELSE external_revenue_history.yoy END,
                cumulative_revenue=CASE WHEN external_revenue_history.cumulative_revenue IS NULL THEN excluded.cumulative_revenue ELSE external_revenue_history.cumulative_revenue END,
                cumulative_yoy=CASE WHEN external_revenue_history.cumulative_yoy IS NULL THEN excluded.cumulative_yoy ELSE external_revenue_history.cumulative_yoy END,
                source_url=CASE WHEN COALESCE(external_revenue_history.source_url,'')='' THEN excluded.source_url ELSE external_revenue_history.source_url END,
                source_date=CASE WHEN COALESCE(external_revenue_history.source_date,'')='' THEN excluded.source_date ELSE external_revenue_history.source_date END,
                update_time=excluded.update_time
        """
        before = 0
        after = 0
        try:
            with db.lock:
                cur = db.conn.cursor()
                before = int(cur.execute("SELECT COUNT(*) FROM external_revenue_history").fetchone()[0] or 0)
                cur.executemany(sql_insert_ignore if append_only else sql_upsert_repair, rows)
                db.conn.commit()
                after = int(cur.execute("SELECT COUNT(*) FROM external_revenue_history").fetchone()[0] or 0)
            log_info(f"[R5N][EXTERNAL_REVENUE_HISTORY][WRITE] rows_input={len(rows)} inserted_or_existing_delta={after-before} append_only={append_only}")
            return int(after - before)
        except Exception as exc:
            log_warning(f"[R5N][EXTERNAL_REVENUE_HISTORY][WRITE_FAIL] {exc}")
            return 0

    def validate_selected_revenue_months(self, months: list[str], db: DBManager | None = None) -> pd.DataFrame:
        """R5N8D：驗證 UI 選取月份的 final cache / normalized cache / DB 閉環。

        注意：
        - SII 上市月營收應由 TWSE Index04 C04003 建立。
        - OTC 上櫃月營收不是 Index04 範圍；僅列示既有 MOPS/TPEX 閉環狀態，不將其誤判為 Index04 缺口。
        - legacy revenue_YYYYMM.csv 僅為相容輸出，不再作為正式 PASS 的唯一依據。
        """
        norm_months = []
        for m in (months or []):
            mm = RevenueAccelerationEngine.normalize_month(m)
            if mm and mm not in norm_months:
                norm_months.append(mm)
        rows = []
        for mm in norm_months:
            legacy_cache_path = self.cache_path_for_month(mm)
            sii_cache_path = self.monthly_cache_path(mm, "sii")
            otc_cache_path = self.monthly_cache_path(mm, "otc")
            norm_sii_path = self.normalized_cache_path(mm, "sii")
            norm_otc_path = self.normalized_cache_path(mm, "otc")
            sii_cache_df = self.read_month_cache(mm, "sii")
            otc_cache_df = self.read_month_cache(mm, "otc")
            legacy_cache_df = self.load_month_cache(mm) if legacy_cache_path.exists() else pd.DataFrame()
            sii_cache_rows = int(len(sii_cache_df)) if sii_cache_df is not None else 0
            otc_cache_rows = int(len(otc_cache_df)) if otc_cache_df is not None else 0
            legacy_rows = int(len(legacy_cache_df)) if legacy_cache_df is not None else 0
            db_rows = db_sii_rows = db_otc_rows = 0
            if db is not None:
                try:
                    with db.lock:
                        cur = db.conn.cursor()
                        row = cur.execute(
                            "SELECT COUNT(*) FROM external_revenue_history WHERE revenue_month=? AND COALESCE(revenue,0)>0",
                            (mm,)
                        ).fetchone()
                        db_rows = int(row[0] or 0) if row else 0
                        row = cur.execute(
                            "SELECT COUNT(*) FROM external_revenue_history WHERE revenue_month=? AND COALESCE(revenue,0)>0 AND COALESCE(market_type,'')='sii'",
                            (mm,)
                        ).fetchone()
                        db_sii_rows = int(row[0] or 0) if row else 0
                        row = cur.execute(
                            "SELECT COUNT(*) FROM external_revenue_history WHERE revenue_month=? AND COALESCE(revenue,0)>0 AND COALESCE(market_type,'')='otc'",
                            (mm,)
                        ).fetchone()
                        db_otc_rows = int(row[0] or 0) if row else 0
                except Exception as exc:
                    log_warning(f"[R5N8D][VALIDATE_DB_FAIL] month={mm}｜{exc}")
            sii_pass = sii_cache_rows > 0 and (db is None or db_sii_rows > 0)
            otc_pass = otc_cache_rows > 0 and (db is None or db_otc_rows > 0)
            not_due = _r5n7d_is_revenue_not_due(mm) and not sii_pass
            rows.append({
                "月份": mm,
                "SII_FinalCache": str(sii_cache_path),
                "SII_FinalCache存在": "YES" if sii_cache_path.exists() and sii_cache_path.stat().st_size > 0 else "NO",
                "SII_NormalizedCache": str(norm_sii_path),
                "SII_NormalizedCache存在": "YES" if norm_sii_path.exists() and norm_sii_path.stat().st_size > 0 else "NO",
                "SII_Cache有效筆數": sii_cache_rows,
                "SII_DB有效筆數": db_sii_rows,
                "SII驗收結果": "PASS" if sii_pass else ("NOT_DUE" if not_due else "FAIL"),
                "OTC_FinalCache": str(otc_cache_path),
                "OTC_FinalCache存在": "YES" if otc_cache_path.exists() and otc_cache_path.stat().st_size > 0 else "NO",
                "OTC_NormalizedCache": str(norm_otc_path),
                "OTC_NormalizedCache存在": "YES" if norm_otc_path.exists() and norm_otc_path.stat().st_size > 0 else "NO",
                "OTC_Cache有效筆數": otc_cache_rows,
                "OTC_DB有效筆數": db_otc_rows,
                "OTC驗收結果": "PASS" if otc_pass else ("NOT_DUE" if _r5n7d_is_revenue_not_due(mm) else "WARN"),
                "Legacy相容Cache": str(legacy_cache_path),
                "Legacy有效筆數": legacy_rows,
                "Cache有效筆數合計": sii_cache_rows + otc_cache_rows,
                "DB有效筆數合計": db_rows,
                "驗收結果": "PASS" if sii_pass else ("NOT_DUE" if not_due else "FAIL"),
                "驗收說明": "SII final/normalized cache 與 DB 均有有效月營收" if sii_pass else ("月報未到期，非正式月報缺失" if not_due else "缺少SII final cache或DB有效資料"),
            })
        out_df = pd.DataFrame(rows)
        try:
            for mm in norm_months:
                _r5n8d_write_official_source_gate_csv(mm, out_df[out_df["月份"].astype(str).eq(mm)].copy(), "revenue_cache_db_validate")
        except Exception:
            pass
        return out_df

    def download_mops_history_month_cache(self, target_month: str) -> pd.DataFrame:
        """R4F：補指定歷史月份月營收（例如 202602/202603）。

        OpenAPI t187ap05 多數情境只回「最新月」；因此缺歷史月份時，必須改用
        MOPS ajax_t21sc04 指定 year/month/TYPEK 逐月抓取。此方法只產生快取資料，
        回傳後仍由 supplement_missing_only 以 append-only 寫入 history，不覆蓋既有資料。
        """
        m = RevenueAccelerationEngine.normalize_month(target_month)
        if not m:
            return pd.DataFrame()
        year = int(m[:4]); month = int(m[4:6]); roc_year = year - 1911
        url = "https://mops.twse.com.tw/mops/web/ajax_t21sc04"
        parts, errors = [], []
        for market_label, typek in [("上市", "sii"), ("上櫃", "otc")]:
            try:
                resp = requests.post(
                    url,
                    data={"encodeURIComponent": "1", "step": "1", "firstin": "1", "off": "1", "TYPEK": typek, "year": str(roc_year), "month": str(month)},
                    timeout=45,
                    headers={"User-Agent": "Mozilla/5.0", "Referer": "https://mops.twse.com.tw/mops/web/t21sc04_ifrs"},
                )
                resp.raise_for_status()
                html = resp.text or ""
                try:
                    raw_mops_dir = _r5n7d_revenue_pipeline_dir("raw", normalize_market_type(typek), "mops_t21sc03")
                    raw_mops_file = raw_mops_dir / f"mops_t21sc03_{m}_{normalize_market_type(typek) or typek}.html"
                    _r5n7d_archive_existing_file(raw_mops_file, reason="raw")
                    raw_mops_file.write_text(html, encoding="utf-8")
                    _r5n7d_append_manifest({"stage": "raw", "source_key": "mops_t21sc03", "revenue_month": m, "market_type": normalize_market_type(typek), "path": str(raw_mops_file), "bytes": int(raw_mops_file.stat().st_size), "status": "PASS", "request_url": url})
                except Exception as raw_exc:
                    log_warning(f"[R5N7D][REVENUE_RAW_MOPS_SAVE_FAIL] month={m} market={typek}｜{raw_exc}")
                if not html.strip() or ("查無資料" in html and "公司代號" not in html):
                    errors.append(f"{market_label}:{m}:empty_html")
                    continue
                tables, parser_used, read_err = safe_read_html_tables(html, source_label=f"MOPS_T21SC04_{market_label}_{m}")
                if not tables:
                    reason_code = "DEPENDENCY_MISSING" if "No module named" in read_err or "Missing optional dependency" in read_err else "PARSE_ROWS_ZERO"
                    errors.append(f"{market_label}:{m}:read_html:{read_err}")
                    self._emit_cache_trace(m, "PARSE", "FAIL", 0, None, reason_code, read_err)
                    continue
                self._emit_cache_trace(m, "PARSE", "PASS", len(tables), None, "", f"parser={parser_used}")
                parsed_parts = []
                for t in tables:
                    ft = self._flatten_revenue_html_table(t)
                    if ft is None or ft.empty:
                        continue
                    parsed, err = self.parse_revenue_openapi(ft, source_label=f"MOPS_T21SC04_{market_label}_{m}")
                    if parsed is not None and not parsed.empty:
                        parsed["revenue_month"] = m
                        parsed["market_type"] = normalize_market_type(typek)
                        parsed["source_url"] = f"MOPS_T21SC04:{typek}:{m}"
                        parsed_parts.append(parsed)
                if parsed_parts:
                    part = pd.concat(parsed_parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")
                    parts.append(part)
                    log_info(f"[REVENUE][MOPS_T21SC04_HISTORY][{market_label}] month={m} rows={len(part)}")
                else:
                    errors.append(f"{market_label}:{m}:parse_empty")
            except Exception as exc:
                errors.append(f"{market_label}:{m}:{exc}")
                log_warning(f"[REVENUE][MOPS_T21SC04_HISTORY][{market_label}] failed month={m}｜{exc}")
        if not parts:
            log_warning(f"[REVENUE][MOPS_T21SC04_HISTORY] month={m} rows=0 errors={' ; '.join(errors)}")
            return pd.DataFrame()
        df = pd.concat(parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")
        df["source_date"] = f"{year}-{month:02d}"
        df["update_time"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        monthly_cache_path = self.write_month_cache(df, m, source_url=f"OFFICIAL_MOPS_T21SC04_HISTORY:{m}")
        # R5N7：MOPS 上櫃月營收 raw/normalized 另存 otc/mops_t21sc03 便於現場查核。
        try:
            otc_df = df[df.get("market_type", "").astype(str).map(normalize_market_type).eq("otc")].copy() if "market_type" in df.columns else pd.DataFrame()
            if otc_df is not None and not otc_df.empty:
                otc_file = REVENUE_MOPS_T21SC03_OTC_DIR / f"revenue_{m}_otc.csv"
                otc_file.parent.mkdir(parents=True, exist_ok=True)
                otc_df.to_csv(otc_file, index=False, encoding="utf-8-sig")
        except Exception as _otc_cache_exc:
            log_warning(f"[R5N7][REVENUE_OTC_CACHE][WRITE_FAIL] month={m}｜{_otc_cache_exc}")
        batch_cache_path = self.save_cache_df(df, source_tag=f"mops_t21sc04_{m}")
        cache_path = monthly_cache_path or batch_cache_path
        df["source_url"] = "OFFICIAL_MOPS_T21SC04_HISTORY_CACHE:" + str(cache_path or f"{m}")
        return df[["stock_id", "revenue_month", "market_type", "revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy", "source_date", "source_url", "update_time"]]

    def download_required_history_caches(self, required_months: list[str]) -> pd.DataFrame:
        """R4F：逐月補缺歷史月營收，不使用最新月資料假補。"""
        parts = []
        for m in [RevenueAccelerationEngine.normalize_month(x) for x in (required_months or [])]:
            if not m:
                continue
            try:
                part = self.download_mops_history_month_cache(m)
                if part is not None and not part.empty:
                    parts.append(part)
            except Exception as exc:
                log_warning(f"[REVENUE][MOPS_T21SC04_HISTORY] required month failed {m}｜{exc}")
        if not parts:
            return pd.DataFrame()
        return pd.concat(parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")

    def supplement_missing_only(self, existing_df: pd.DataFrame | None, required_months: list[str], force_download: bool = False) -> pd.DataFrame:
        required = [RevenueAccelerationEngine.normalize_month(m) for m in (required_months or [])]
        required = [m for m in required if m]
        if not required:
            return pd.DataFrame()
        existing = existing_df.copy() if isinstance(existing_df, pd.DataFrame) else pd.DataFrame()
        if not existing.empty and "revenue_month" in existing.columns:
            existing["stock_id"] = existing.get("stock_id", "").map(normalize_stock_id)
            existing["revenue_month"] = existing["revenue_month"].map(RevenueAccelerationEngine.normalize_month)
            existing["revenue"] = pd.to_numeric(existing.get("revenue"), errors="coerce")
        cache_df = pd.DataFrame()
        if not force_download:
            # R4F：先掃全部本地快取，避免 latest cache 只有最新月份而補不到歷史缺月。
            cache_df = self.read_all_caches()
            if cache_df is None or cache_df.empty:
                cache_df = self.read_latest_cache()
        if cache_df is None or cache_df.empty:
            cache_df, _, _ = self.download_latest_cache(include_optional=False)
        if cache_df is None or cache_df.empty:
            return pd.DataFrame()
        cache_df = cache_df[cache_df["revenue_month"].astype(str).isin(required)].copy()
        missing_after_cache = [m for m in required if m not in set(cache_df.get("revenue_month", pd.Series(dtype=str)).astype(str).tolist())]
        if missing_after_cache:
            # R5M：latest OpenAPI 只提供最新月時，先用 TWSE index04/C04003 歷史 ZIP 補上市月營收；
            # 若仍缺，再沿用 R4F MOPS t21sc04 補上市/上櫃。
            index04_parts = []
            for mm in missing_after_cache:
                try:
                    part = self.download_twse_index04_c04003_month_cache(mm)
                    if part is not None and not part.empty:
                        index04_parts.append(part)
                except Exception as exc:
                    log_warning(f"[REVENUE][INDEX04_C04003_HISTORY] month={mm} failed｜{exc}")
            if index04_parts:
                index04_df = pd.concat(index04_parts, ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")
                cache_df = pd.concat([cache_df, index04_df], ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="last")
                log_warning(f"[REVENUE][HISTORY_BACKFILL][R5M_INDEX04] missing_after_cache={missing_after_cache} index04_rows={len(index04_df)} months={sorted(index04_df['revenue_month'].astype(str).unique().tolist())}")
            # R5M：C04003 只涵蓋上市公司；仍嘗試 MOPS t21sc04 補上櫃/興櫃同月份，
            # 但以上市 C04003 為優先，不讓 MOPS 解析異常覆蓋已成功的上市快取。
            hist_df = self.download_required_history_caches(missing_after_cache)
            if hist_df is not None and not hist_df.empty:
                before_rows = len(cache_df)
                cache_df = pd.concat([cache_df, hist_df], ignore_index=True).drop_duplicates(["stock_id", "revenue_month"], keep="first")
                log_warning(f"[REVENUE][HISTORY_BACKFILL][R4F_MOPS_SUPPLEMENT] missing_after_cache={missing_after_cache} hist_rows={len(hist_df)} combined_rows_before={before_rows} combined_rows_after={len(cache_df)} months={sorted(hist_df['revenue_month'].astype(str).unique().tolist())}")
            else:
                still_missing = [m for m in missing_after_cache if m not in set(cache_df.get("revenue_month", pd.Series(dtype=str)).astype(str).tolist())]
                if still_missing:
                    log_warning(f"[REVENUE][HISTORY_BACKFILL][PARTIAL] C04003已補上市但仍可能缺上櫃/興櫃月份資料：{still_missing}")
        if cache_df.empty:
            return pd.DataFrame()
        if not existing.empty and {"stock_id", "revenue_month"}.issubset(existing.columns):
            exist_keys = set(zip(existing["stock_id"].astype(str), existing["revenue_month"].astype(str)))
            cache_df = cache_df[~cache_df.apply(lambda r: (str(r.get("stock_id", "")), str(r.get("revenue_month", ""))) in exist_keys, axis=1)].copy()
        cache_df = cache_df[pd.to_numeric(cache_df.get("revenue"), errors="coerce") > 0].copy()
        if cache_df.empty:
            return pd.DataFrame()
        cache_df["source_url"] = cache_df.get("source_url", "").fillna("").astype(str)
        no_source_mask = cache_df["source_url"].astype(str).str.strip().eq("")
        cache_df.loc[no_source_mask, "source_url"] = "OFFICIAL_OPENAPI_CACHE:" + str(self.latest_cache_file() or "download_memory")
        log_info(f"[REVENUE][OPENAPI_CACHE][APPEND_ONLY] required_months={required} append_rows={len(cache_df)} months={sorted(cache_df['revenue_month'].astype(str).unique().tolist())} zero_rejected=1 policy=INSERT_OR_IGNORE_ONLY")
        return cache_df[["stock_id", "revenue_month", "revenue", "mom", "yoy", "cumulative_revenue", "cumulative_yoy", "source_date", "source_url", "update_time"]].drop_duplicates(["stock_id", "revenue_month"], keep="last")



class AnnualEPSCacheEngine:
    """
    R5G_ANNUAL_EPS_CACHE_ENGINE_20260607
    目的：
    - annual_eps_history 不再依賴單一 index05 / MOPS / OpenAPI。
    - 建立五層備援：Cache -> Local File -> Official EPS OpenAPI 2025Q4 -> Index05 Selenium -> MOPS。
    - 任一來源成功後，立即回寫 data/annual_eps_cache/annual_eps_{year}.csv，
      下次啟動可直接由 cache 補回 annual_eps_history，降低網站改版與 EXE 環境風險。
    """

    SUCCESS_STATUS = {"exists", "imported"}

    def __init__(self, owner):
        self.owner = owner
        self.cache_dir = RUNTIME_DIR / "data" / "annual_eps_cache"
        self.cache_dir.mkdir(parents=True, exist_ok=True)

    def _count_db_rows(self, fiscal_year: int) -> int:
        try:
            if not self.owner._table_exists("annual_eps_history"):
                return 0
            with self.owner.db.lock:
                row = self.owner.db.conn.cursor().execute(
                    "SELECT COUNT(*) FROM annual_eps_history WHERE fiscal_year=? AND eps_full_year IS NOT NULL",
                    (int(fiscal_year),)
                ).fetchone()
            return int(row[0] or 0) if row else 0
        except Exception as exc:
            log_warning(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CACHE] count_db_rows failed fiscal_year={fiscal_year}｜{exc}")
            return 0

    def _cache_paths(self, fiscal_year: int) -> list[Path]:
        fiscal_year = int(fiscal_year)
        roc_year = fiscal_year - 1911
        roots = [
            RUNTIME_DIR / "data" / "annual_eps_cache",
            RUNTIME_DIR / "data" / "eps_cache",
            RUNTIME_DIR / "data" / "eps",
            BASE_DIR / "data" / "annual_eps_cache",
            BASE_DIR / "data" / "eps_cache",
            BASE_DIR / "data" / "eps",
        ]
        names = [
            f"annual_eps_{fiscal_year}.csv",
            f"annual_eps_{fiscal_year}.json",
            f"annual_eps_history_{fiscal_year}.csv",
            f"annual_eps_history_{fiscal_year}.json",
            f"{fiscal_year}Q4_annual_eps_cache.csv",
            f"{fiscal_year}Q4_annual_eps_cache.json",
            f"{roc_year}Q4_annual_eps_cache.csv",
            f"{roc_year}Q4_annual_eps_cache.json",
            f"114Q4_annual_eps_cache.csv" if fiscal_year == 2025 else "",
            f"2025Q4_annual_eps_cache.csv" if fiscal_year == 2025 else "",
        ]
        out = []
        seen = set()
        for root in roots:
            try:
                for name in names:
                    if not name:
                        continue
                    path = Path(root) / name
                    key = str(path)
                    if key not in seen:
                        seen.add(key)
                        out.append(path)
            except Exception:
                continue
        return out

    @staticmethod
    def _pick_column(df: pd.DataFrame, aliases: list[str]) -> str | None:
        if df is None or df.empty:
            return None
        norm_map = {str(c).strip().lower().replace(" ", "").replace("_", ""): c for c in df.columns}
        for alias in aliases:
            key = str(alias).strip().lower().replace(" ", "").replace("_", "")
            if key in norm_map:
                return norm_map[key]
        for c in df.columns:
            s = str(c).strip().lower()
            if any(str(a).strip().lower() in s for a in aliases):
                return c
        return None

    def _read_cache_file(self, path: Path, fiscal_year: int) -> pd.DataFrame:
        path = Path(path)
        if not path.exists() or path.stat().st_size <= 0:
            return pd.DataFrame()
        suffix = path.suffix.lower()
        if suffix == ".json":
            raw = safe_read_json_auto(path)
        elif suffix == ".csv":
            raw = safe_read_csv_auto(path)
        else:
            return pd.DataFrame()
        if raw is None or raw.empty:
            return pd.DataFrame()

        stock_col = self._pick_column(raw, ["stock_id", "公司代號", "證券代號", "代號", "Code"])
        name_col = self._pick_column(raw, ["stock_name", "公司名稱", "公司簡稱", "證券名稱", "Name"])
        eps_col = self._pick_column(raw, ["eps_full_year", "annual_eps", "eps_cumulative", "基本每股盈餘", "EPS", "basic_eps"])
        year_col = self._pick_column(raw, ["fiscal_year", "年度", "year"])
        q_col = self._pick_column(raw, ["quarter", "季別", "season"])

        if stock_col is None or eps_col is None:
            raise ValueError(f"cache格式不符，找不到 stock_id/eps 欄位：{path}")

        out = pd.DataFrame()
        out["stock_id"] = raw[stock_col].map(normalize_stock_id)
        out["stock_name"] = raw[name_col].astype(str).str.strip() if name_col in raw.columns else ""
        out["eps_full_year"] = pd.to_numeric(raw[eps_col], errors="coerce")

        if year_col in raw.columns:
            y = pd.to_numeric(raw[year_col], errors="coerce")
            valid_year = (y == int(fiscal_year)) | (y == int(fiscal_year) - 1911)
            if valid_year.notna().any():
                out = out.loc[valid_year.fillna(False)].copy()
        if q_col in raw.columns:
            q = pd.to_numeric(raw[q_col], errors="coerce")
            # R5G：cache 原則上只收 Q4 年度 EPS；若舊 cache 沒 quarter 欄位，視為已整理年度檔。
            out = out.loc[q.fillna(4).eq(4)].copy()

        out["fiscal_year"] = int(fiscal_year)
        out["fiscal_year_roc"] = int(fiscal_year) - 1911
        out["quarter"] = 4
        out["eps_cumulative"] = out["eps_full_year"]
        out["eps_quarter"] = np.nan
        out["eps_prev_cumulative"] = np.nan
        out["eps_calc_method"] = "R5G_CACHE_ANNUAL_EPS"
        out["source_type"] = "ANNUAL_EPS_CACHE"
        out["source_url"] = "LOCAL_CACHE"
        out["source_file"] = str(path)
        out["source_date"] = f"{int(fiscal_year)}Q4"
        out["update_time"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        out = out.dropna(subset=["stock_id", "eps_full_year"])
        out = out[out["stock_id"].astype(str).str.fullmatch(r"\d{4}", na=False)].copy()
        out = out.drop_duplicates(subset=["stock_id", "fiscal_year"], keep="last")
        return out

    def try_import_cache(self, fiscal_year: int, force: bool = False) -> dict:
        result = {"status": "skip", "rows": 0, "source": "ANNUAL_EPS_CACHE", "source_file": "", "message": ""}
        try:
            existing = self._count_db_rows(fiscal_year)
            if existing > 0 and not force:
                self.save_cache_from_db(fiscal_year)
                result.update({"status": "exists", "rows": existing, "message": "annual_eps_history 已有資料，已同步確認 cache"})
                return result

            errors = []
            for path in self._cache_paths(fiscal_year):
                if not path.exists():
                    continue
                try:
                    parsed = self._read_cache_file(path, fiscal_year)
                    rows = self.owner._write_annual_eps_history(parsed, fiscal_year, source_label="ANNUAL_EPS_CACHE")
                    if rows > 0:
                        result.update({"status": "imported", "rows": rows, "source_file": str(path), "message": "已由年度EPS Cache補入 annual_eps_history"})
                        log_info(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CACHE] imported rows={rows} file={path}")
                        return result
                    errors.append(f"write_zero:{path}")
                except Exception as exc:
                    errors.append(f"{path}:{exc}")
                    log_warning(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CACHE] cache candidate failed file={path}｜{exc}")

            result.update({"status": "missing_cache", "rows": 0, "message": "; ".join(errors[:5]) if errors else "找不到可用年度EPS cache"})
            return result
        except Exception as exc:
            result.update({"status": "error", "rows": 0, "message": str(exc)})
            log_warning(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CACHE] try_import_cache failed fiscal_year={fiscal_year}｜{exc}")
            return result

    def save_cache_from_db(self, fiscal_year: int) -> dict:
        result = {"status": "skip", "rows": 0, "cache_file": "", "message": ""}
        try:
            if not self.owner._table_exists("annual_eps_history"):
                result.update({"status": "missing_table", "message": "annual_eps_history 不存在"})
                return result
            df = self.owner._read_sql(
                "SELECT stock_id, fiscal_year, fiscal_year_roc, quarter, eps_full_year, eps_cumulative, eps_quarter, "
                "eps_prev_cumulative, eps_calc_method, source_type, source_url, source_file, source_date, update_time "
                "FROM annual_eps_history WHERE fiscal_year=? AND eps_full_year IS NOT NULL",
                [int(fiscal_year)]
            )
            if df is None or df.empty:
                result.update({"status": "no_data", "message": "annual_eps_history 無可寫入 cache 資料"})
                return result
            self.cache_dir.mkdir(parents=True, exist_ok=True)
            cache_file = self.cache_dir / f"annual_eps_{int(fiscal_year)}.csv"
            df.to_csv(cache_file, index=False, encoding="utf-8-sig")
            result.update({"status": "saved", "rows": int(len(df)), "cache_file": str(cache_file), "message": "年度EPS已寫入cache"})
            log_info(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CACHE] saved rows={len(df)} file={cache_file}")
            return result
        except Exception as exc:
            result.update({"status": "error", "message": str(exc)})
            log_warning(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CACHE] save_cache_from_db failed fiscal_year={fiscal_year}｜{exc}")
            return result

    def _run_source(self, source_name: str, fn, fiscal_year: int, force: bool = False) -> dict:
        try:
            log_info(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CHAIN] start source={source_name} fiscal_year={fiscal_year}")
            result = fn(fiscal_year, force=force)
            if not isinstance(result, dict):
                result = {"status": "unknown", "rows": 0, "message": str(result)}
            log_info(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CHAIN] done source={source_name} result={result}")
            if str(result.get("status", "")).lower() in self.SUCCESS_STATUS or int(result.get("rows", 0) or 0) > 0:
                cache_result = self.save_cache_from_db(fiscal_year)
                result["cache_result"] = cache_result
            return result
        except Exception as exc:
            log_warning(f"[HIGH_GROWTH][R5G_ANNUAL_EPS_CHAIN] source={source_name} failed｜{exc}")
            return {"status": "error", "rows": 0, "source": source_name, "message": str(exc)}

    def ensure(self, fiscal_year: int, force: bool = False) -> dict:
        fiscal_year = int(fiscal_year)
        trace = []
        trace_engine = ExternalDataTraceEngine(self.owner.db, run_id=f"AnnualEPS_{fiscal_year}_{datetime.now().strftime('%Y%m%d_%H%M%S')}")
        trace_engine.event(
            "AnnualEPS", "R5H_CHAIN", "START", "PASS",
            target_table="annual_eps_history",
            source_date=f"{fiscal_year}Q4",
            fail_reason_detail="Cache>LocalFile>OfficialOpenAPI_Q4>Index05Selenium>MOPS"
        )
        log_info(f"[HIGH_GROWTH][R5H_ANNUAL_EPS_CHAIN] start fiscal_year={fiscal_year} order=Cache>LocalFile>OfficialOpenAPI_Q4>Index05Selenium>MOPS")

        # R5I：每層來源都寫入 external_data_trace_event，並在最後做 annual_eps_history verify。
        chain = [
            ("CACHE", self.try_import_cache),
            ("LOCAL_FILE_114Q4_2025Q4", self.owner.ensure_annual_eps_from_local_114q4_file),
            ("OFFICIAL_EPS_OPENAPI_2025Q4", self.owner.ensure_annual_eps_from_official_openapi_q4),
            ("INDEX05_SELENIUM_C05001", self.owner.ensure_annual_eps_from_twse_c05001),
            ("MOPS_T163SB04", self.owner.ensure_annual_eps_from_mops),
        ]

        for source_name, fn in chain:
            start_ts = time.time()
            result = self._run_source(source_name, fn, fiscal_year, force=force)
            elapsed_ms = round((time.time() - start_ts) * 1000, 2)
            result["source_name"] = source_name
            trace.append(result)
            status_raw = str(result.get("status", "")).lower()
            rows = int(result.get("rows", 0) or 0)
            verify_count = self._count_db_rows(fiscal_year)
            event_status = "PASS" if (status_raw in self.SUCCESS_STATUS or rows > 0 or verify_count > 0) else ("WARN" if status_raw in ("skip", "missing_file", "no_data") else "FAIL")
            reason = "" if event_status == "PASS" else ExternalDataTraceEngine.infer_fail_reason(
                stage="SOURCE",
                status=event_status,
                rows_written=rows,
                verify_count=verify_count,
                detail=str(result.get("message", ""))
            )
            trace_engine.event(
                "AnnualEPS", source_name, "SOURCE", event_status,
                target_table="annual_eps_history",
                rows_parsed=rows,
                rows_written=rows,
                verify_count=verify_count,
                fail_reason_code=reason,
                fail_reason_detail=str(result.get("message", "")),
                source_file=str(result.get("source_file", "")),
                source_date=f"{fiscal_year}Q4",
                elapsed_ms=elapsed_ms,
            )
            if status_raw in self.SUCCESS_STATUS or rows > 0 or verify_count > 0:
                final = {
                    "status": "success",
                    "rows": rows or verify_count,
                    "winning_source": source_name,
                    "trace": trace,
                    "message": f"R5I年度EPS備援成功：{source_name}",
                    "trace_run_id": trace_engine.run_id,
                }
                trace_engine.verify_core_table(
                    "AnnualEPS", "annual_eps_history",
                    "fiscal_year=? AND eps_full_year IS NOT NULL",
                    (fiscal_year,), min_rows=1
                )
                log_info(f"[HIGH_GROWTH][R5I_ANNUAL_EPS_CHAIN] success winning_source={source_name} rows={rows} verify={verify_count}")
                return final

        verify_count = self._count_db_rows(fiscal_year)
        trace_engine.fail(
            "AnnualEPS", "R5H_CHAIN", "VERIFY",
            reason_code="VERIFY_ROWS_ZERO",
            reason_detail=f"R5H/R5I五層備援皆未取得年度EPS；annual_eps_history fiscal_year={fiscal_year} verify_count={verify_count}",
            target_table="annual_eps_history",
            verify_count=verify_count,
            source_date=f"{fiscal_year}Q4",
        )
        final = {
            "status": "failed",
            "rows": 0,
            "winning_source": "",
            "trace": trace,
            "message": "R5I五層備援皆未取得年度EPS；請看00A_外部資料健康檢查/00B_外部資料Trace明細",
            "trace_run_id": trace_engine.run_id,
        }
        log_warning(f"[HIGH_GROWTH][R5I_ANNUAL_EPS_CHAIN] failed fiscal_year={fiscal_year} trace={trace}")
        return final


class EPSForecastEngine:
    """EPS 實績/預測引擎（V4.7 官方年度EPS雙來源修正版）。

    修正重點：
    1. 正式 EPS 主來源改為 MOPS ajax_t163sb04 POST（綜合損益表彙總報表），不再依賴 TWSE index05 HTML/ZIP 掃描。
    2. 啟動高成長 EPS 報表時，先自動補入：2026Q1、2025Q1 的正式季度 EPS，以及 2025Q4 的全年 EPS。
    3. MOPS Q2/Q3/Q4 為累積 EPS；若未來要匯入單季 EPS，必須用本季累積 EPS - 前季累積 EPS，Q1 則可直接作單季 EPS。
    4. EPS_TTM 仍可用於 TTM 追蹤候選，但不可誤當全年 EPS 或 Q1 EPS。
    """

    def __init__(self, db: DBManager, base_year: int = HIGH_GROWTH_BASE_YEAR, track_year: int = HIGH_GROWTH_TRACK_YEAR):
        self.db = db
        self.base_year = int(base_year)
        self.track_year = int(track_year)
        self.ensure_schema()

    def _table_exists(self, table_name: str) -> bool:
        try:
            with self.db.lock:
                row = self.db.conn.cursor().execute(
                    "SELECT name FROM sqlite_master WHERE type='table' AND name=?", (table_name,)
                ).fetchone()
            return row is not None
        except Exception:
            return False

    def _read_sql(self, sql: str, params=None) -> pd.DataFrame:
        try:
            with self.db.lock:
                return pd.read_sql_query(sql, self.db.conn, params=params or [])
        except Exception as exc:
            log_warning(f"[EPSForecastEngine] SQL讀取失敗：{exc}｜SQL={sql[:120]}")
            return pd.DataFrame()

    def ensure_schema(self):
        try:
            with self.db.lock:
                cur = self.db.conn.cursor()
                cur.execute("""
                CREATE TABLE IF NOT EXISTS annual_eps_history (
                    stock_id TEXT,
                    fiscal_year INTEGER,
                    eps_full_year REAL,
                    eps_cumulative REAL,
                    eps_quarter REAL,
                    eps_prev_cumulative REAL,
                    eps_calc_method TEXT,
                    source_type TEXT,
                    source_url TEXT,
                    source_date TEXT,
                    update_time TEXT,
                    PRIMARY KEY(stock_id, fiscal_year)
                )
                """)
                cur.execute("CREATE INDEX IF NOT EXISTS idx_annual_eps_history_stock_year ON annual_eps_history(stock_id, fiscal_year)")
                # V4.8 EPS_CUMULATIVE_QUARTER_FIX：年度表保留原 eps_full_year，並新增累計/單季欄位作來源追溯。
                for _col, _ddl in [
                    ("fiscal_year_roc", "fiscal_year_roc INTEGER"),
                    ("quarter", "quarter INTEGER"),
                    ("eps_cumulative", "eps_cumulative REAL"),
                    ("eps_quarter", "eps_quarter REAL"),
                    ("eps_prev_cumulative", "eps_prev_cumulative REAL"),
                    ("eps_calc_method", "eps_calc_method TEXT"),
                    ("source_type", "source_type TEXT"),
                    ("market_type", "market_type TEXT"),
                    ("source_url", "source_url TEXT"),
                    ("source_file", "source_file TEXT"),
                    ("source_date", "source_date TEXT"),
                    ("update_time", "update_time TEXT"),
                ]:
                    try:
                        cur.execute(f"ALTER TABLE annual_eps_history ADD COLUMN {_ddl}")
                    except Exception:
                        pass
                # quarterly_financial_history 必須同時保存官方累計EPS與反推單季EPS。
                # eps 欄保留相容性，固定等於 eps_quarter，不再把累計值重複加總。
                for _col, _ddl in [
                    ("eps_cumulative", "eps_cumulative REAL"),
                    ("eps_quarter", "eps_quarter REAL"),
                    ("eps_prev_cumulative", "eps_prev_cumulative REAL"),
                    ("eps_calc_method", "eps_calc_method TEXT"),
                    ("source_type", "source_type TEXT"),
                    ("market_type", "market_type TEXT"),
                ]:
                    try:
                        cur.execute(f"ALTER TABLE quarterly_financial_history ADD COLUMN {_ddl}")
                    except Exception:
                        pass
                try:
                    cur.execute("CREATE UNIQUE INDEX IF NOT EXISTS uq_qfh_stock_fyq ON quarterly_financial_history(stock_id, fiscal_year_quarter)")
                except Exception:
                    pass
                self.db.conn.commit()
        except Exception as exc:
            log_warning(f"[EPSForecastEngine] annual_eps_history schema建立失敗：{exc}")

    @staticmethod
    def normalize_quarter_token(value) -> str:
        s = str(value or "").strip().upper().replace(" ", "")
        if not s or s in ("NAN", "NONE", "NULL", "<NA>"):
            return ""
        s = s.replace("年第", "Q").replace("季", "").replace("-", "").replace("_", "")
        m = re.match(r"^(\d{2,3})/?Q?0?([1-4])$", s)
        if m:
            y = int(m.group(1)); q = int(m.group(2))
            if y < 1000:
                y += 1911
            return f"{y}Q{q}"
        m = re.match(r"^(\d{4})/?Q?0?([1-4])$", s)
        if m:
            return f"{int(m.group(1))}Q{int(m.group(2))}"
        return s


