            {"項目": "年度EPS Gate", "內容": f"annual_eps_history_{self.eps_engine.base_year} rows={annual_eps_rows}; min_required={HIGH_GROWTH_MIN_ANNUAL_EPS_ROWS_FOR_FORMAL_REPORT}"},
            {"項目": "主選股模型", "內容": high_growth_model_definition_text("ZH")},
